prompt --application/shared_components/user_interface/lovs/lov_funcionarios_activos
begin
wwv_flow_api.create_list_of_values(
 p_id=>wwv_flow_api.id(576600453834861047)
,p_lov_name=>'LOV_FUNCIONARIOS_ACTIVOS'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'    E.ID_EMPLEADO,',
'    E.NOMBRE || '' '' || E.PRIMER_APELLIDO || '' '' || E.SEGUNDO_APELLIDO AS NOMBRE',
'FROM EMPLEADOS E',
'INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'INNER JOIN EMPLEADOS@CONSULTA_ICT EMP ON E.ID_EMPLEADO = EMP.CODIGO_EMPLEADO_SIRH',
'INNER JOIN USUARIOS@CONSULTA_ICT USU ON EMP.CODIGO_EMPLEADO = USU.CODIGO_EMPLEADO',
'WHERE MP.INDICADOR_VIGENTE = 1 ',
'AND EMP.CODIGO_ESTADO = 1 ',
'AND USU.ESTADO = 1',
'ORDER BY NOMBRE ASC;'))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_return_column_name=>'ID_EMPLEADO'
,p_display_column_name=>'NOMBRE'
,p_group_sort_direction=>'ASC'
,p_default_sort_column_name=>'NOMBRE'
,p_default_sort_direction=>'ASC'
);
end;
/
