 p_id=>wwv_flow_api.id(317153826398382236)
,p_lov_name=>'LOV_PERIODOS_HABILES'
,p_lov_query=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/*SELECT (EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, -12 * LEVEL)) + 0) || ''-'' ||',
'       (EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, -12 * LEVEL)) + 1) AS R',
'FROM DUAL',
'CONNECT BY LEVEL <= EXTRACT(YEAR FROM SYSDATE) - 2020 + 1',
'ORDER BY R;*/',
'',
'',
'',
'SELECT (start_year) || ''-'' || (start_year + 1) AS R',
'FROM (',
'    SELECT 2020 + LEVEL - 1 AS start_year',
'    FROM dual',
'    CONNECT BY 2020 + LEVEL - 1 <= EXTRACT(YEAR FROM SYSDATE)',
')',
'ORDER BY R;'))
,p_source_type=>'SQL'
,p_location=>'LOCAL'
,p_return_column_name=>'R'
,p_display_column_name=>'R'
,p_group_sort_direction=>'ASC'
,p_default_sort_direction=>'ASC'
);
end;
/
