wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(568472501677446827)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_APROBAR_VACACIONES'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_cursor SYS_REFCURSOR;',
'    vNombreJefe VARCHAR2(100);',
'	vId_Jefe NUMBER; ',
'    vcorreo_destino_emp VARCHAR2(255);',
'    vcorreo_destino_jefe VARCHAR2(255);',
'    v_resultado NUMBER;',
'    v_id_empleado_aprueba NUMBER;',
'    v_nombre_empleado_aprueba VARCHAR2(255);',
'    vid_estado NUMBER;',
'    v_text_cant_dias VARCHAR2(50);',
'',
'BEGIN',
unistr('    -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'    CASE :ID_MODULO_SIS',
'        WHEN 1 THEN ',
'            vid_estado := 11;',
'        WHEN 2 THEN ',
'            vid_estado := 4;',
'        ELSE ',
'            vid_estado := NULL;',
'    END CASE;',
'  ',
'    v_id_empleado_aprueba := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'    v_nombre_empleado_aprueba := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_id_empleado_aprueba);',
'    ',
'    PKG_GESTION.sp_aprobar_solicitud(',
unistr('        PId_Empleado => :P2_ID_EMPLEADO, -- Reemplaza con el item de tu p\00E1gina que contiene el ID del empleado'),
unistr('        PId_Solicitud => :P2_ID_SOLICITUD_VACACION, -- Reemplaza con el item de tu p\00E1gina que contiene el ID de la solicitud'),
unistr('        PId_Estado => vid_estado,     -- Reemplaza con el item de tu p\00E1gina que contiene el ID del estado'),
'        PId_Jefatura =>  v_id_empleado_aprueba,      -- Asumiendo que el ID de la jefatura es el usuario de APEX',
unistr('        PId_Sustituye => :P2_ID_SUSTITUYE, -- Reemplaza con el item de tu p\00E1gina que contiene el ID del sustituto'),
'        POUT_Resultado => v_resultado',
'    );',
'    ',
'    IF v_resultado = 1 THEN',
'        ',
unistr('        v_cursor := PKG_PLANI.f_obtener_jefe_x_cod_sirh(:P2_ID_EMPLEADO); -- Llamada a la funci\00F3n'),
'        FETCH v_cursor INTO vId_Jefe, vNombreJefe;',
'        CLOSE v_cursor;',
'',
'        -- Obtener el correo del funcionario y jefe',
'        vcorreo_destino_emp := PKG_PLANI.f_get_correo_emp_x_cod_sirh(:P2_ID_EMPLEADO);',
'        vcorreo_destino_jefe := PKG_PLANI.f_get_correo_emp_x_cod_sirh(vId_Jefe);',
'        ',
'        v_text_cant_dias := TO_CHAR(:P2_DIAS_VACACIONES);    ',
'    ',
'        IF :P2_DIAS_VACACIONES < 1 THEN',
'            v_text_cant_dias := ''0.5'';',
'        END IF;',
'        ',
unistr('      -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'      CASE :ID_MODULO_SIS',
'        WHEN 1 THEN ',
'            PKG_CORREOS.sp_enviar_correo_html(',
'               p_destinatario_in => vcorreo_destino_emp,',
'               p_cc_in => vcorreo_destino_jefe,',
'               p_id_mensaje => 5,',
'               p_parametros => ''NOMBRE='' || :P2_NOMBRE_COMPLETO || ',
'                               '',ID_SOLICITUD_VACACION='' || :P2_ID_SOLICITUD_VACACION ||',
'                               '',PERIODO='' || :P2_PERIODO ||',
'                               '',FECHA_INICIAL='' || :P2_DESDE || ',
'                               '',FECHA_FINAL='' || :P2_HASTA || ',
'                               '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                               '',ID_EMPLEADO_APRUEBA='' || v_nombre_empleado_aprueba',
'           );',
'        WHEN 2 THEN',
'           PKG_CORREOS.sp_enviar_correo_html(',
'               p_destinatario_in => vcorreo_destino_emp,',
'               p_cc_in => NULL,',
'               p_id_mensaje => 5,',
'               p_parametros => ''NOMBRE='' || :P2_NOMBRE_COMPLETO || ',
'                               '',ID_SOLICITUD_VACACION='' || :P2_ID_SOLICITUD_VACACION ||',
'                               '',PERIODO='' || :P2_PERIODO ||',
'                               '',FECHA_INICIAL='' || :P2_DESDE || ',
'                               '',FECHA_FINAL='' || :P2_HASTA || ',
'                               '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                               '',ID_EMPLEADO_APRUEBA='' || v_nombre_empleado_aprueba',
'           );',
'        ELSE ',
'            vcorreo_destino_emp := NULL;',
'            vcorreo_destino_jefe := NULL;',
'      END CASE;',
'    END IF;',
'    ',
'    EXCEPTION',
'       WHEN OTHERS THEN',
unistr('	       apex_error.add_error (p_message => ''Error al enviar la notificaci\00F3n: ''|| SQLERRM,'),
'                                 p_display_location => apex_error.c_inline_in_notification);',
'END;'))
,p_process_error_message=>'Error, no se pudo procesar la solicitud'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'aprobar'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_process_success_message=>unistr('La solicitud de vacaciones fue aprobada con \00E9xito')
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(568668800046334317)
,p_process_sequence=>30
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_DENEGAR_VACACIONES'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'',
'    v_cursor SYS_REFCURSOR;',
'    vNombreJefe VARCHAR2(100);',
'	vId_Jefe NUMBER; ',
'    vcorreo_destino_emp VARCHAR2(255);',
'    vcorreo_destino_jefe VARCHAR2(255);',
'    v_id_empleado_deniega NUMBER;',
'    v_nombre_empleado_deniega VARCHAR(255);',
'    vid_estado NUMBER;',
'    v_resultado NUMBER;',
'    v_text_cant_dias VARCHAR2(50);',
'    v_codigo_estado CHAR(2);',
'',
'BEGIN',
unistr('    -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'    CASE :ID_MODULO_SIS',
'        WHEN 1 THEN ',
'            vid_estado := 12;',
'        WHEN 2 THEN ',
'            vid_estado := 5;',
'    ELSE ',
'        vid_estado := NULL;',
'    END CASE;',
'',
'    v_id_empleado_deniega := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'    --Obtenemos el estado de la solicitud de vacaciones ',
'    --v_codigo_estado := PKG_DEVOLUCION.f_get_cod_estado_soli_vaca(:P2_ID_SOLICITUD_VACACION);',
'    ',
'    PKG_DEVOLUCION.sp_devolucion_vacaciones(',
'        PId_Empleado => :P2_ID_EMPLEADO,   ',
'        PDias => :P2_DIAS_VACACIONES,      ',
'        PPeriodo_Inicio => :P2_INICIO_PERIODO,      ',
'        PConsecutivo => :P2_ID_SOLICITUD_VACACION,',
'        PJustificacion => :P2_MOTIVO_DENEGACION,',
'        PId_Modificador => v_id_empleado_deniega,',
'        Pid_estado => vid_estado,',
'        pestado => ''DE'',',
'        --pestado => v_codigo_estado,',
'        pTipoSolicitud => :P2_TIPO_SOLICITUD,',
'        POUT_Resultado => v_resultado',
'    );',
'    ',
'    --v_resultado := 1;',
'    ',
'    IF v_resultado = 1 THEN',
'         -- Obtener datos de la persona que deniega',
'        v_id_empleado_deniega := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'        v_nombre_empleado_deniega := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_id_empleado_deniega);',
'',
unistr('        v_cursor := PKG_PLANI.f_obtener_jefe_x_cod_sirh(:P2_ID_EMPLEADO); -- Llamada a la funci\00F3n'),
'        FETCH v_cursor INTO vId_Jefe, vNombreJefe;',
'        CLOSE v_cursor;',
'',
'       -- Obtener el correo del funcionario y jefe',
'       vcorreo_destino_emp := PKG_PLANI.f_get_correo_emp_x_cod_sirh(:P2_ID_EMPLEADO);',
'       vcorreo_destino_jefe := PKG_PLANI.f_get_correo_emp_x_cod_sirh(vId_Jefe);',
'       ',
'       v_text_cant_dias := TO_CHAR(:P2_DIAS_VACACIONES);    ',
'       ',
'       IF :P2_DIAS_VACACIONES < 1 THEN',
'            v_text_cant_dias := ''0.5'';',
'       END IF;',
'',
unistr('       -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'       CASE :ID_MODULO_SIS',
'            WHEN 1 THEN ',
'                PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_emp,',
'                   p_cc_in => vcorreo_destino_jefe,',
'                   p_id_mensaje => 6,',
'                   p_parametros => ''NOMBRE='' || :P2_NOMBRE_COMPLETO || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P2_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P2_PERIODO ||',
'                                   '',FECHA_INICIAL='' || :P2_DESDE || ',
'                                   '',FECHA_FINAL='' || :P2_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                                   '',ID_EMPLEADO_DENIEGA='' || v_nombre_empleado_deniega ||',
'                                   '',MOTIVO='' || :P2_MOTIVO_DENEGACION',
'               );',
'            WHEN 2 THEN',
'               PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_emp,',
'                   p_cc_in => NULL,',
'                   p_id_mensaje => 6,',
'                   p_parametros => ''NOMBRE='' || :P2_NOMBRE_COMPLETO || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P2_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P2_PERIODO ||',
'                                   '',FECHA_INICIAL='' || :P2_DESDE || ',
'                                   '',FECHA_FINAL='' || :P2_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                                   '',ID_EMPLEADO_DENIEGA='' || v_nombre_empleado_deniega ||',
'                                   '',MOTIVO='' || :P2_MOTIVO_DENEGACION',
'               );',
'            ELSE ',
'                vcorreo_destino_emp := NULL;',
'                vcorreo_destino_jefe := NULL;',
'          END CASE;',
'    END IF;',
'    ',
'    EXCEPTION',
'       WHEN OTHERS THEN',
unistr('	       apex_error.add_error (p_message => ''Error al enviar la notificaci\00F3n: ''|| SQLERRM,'),
'                                 p_display_location => apex_error.c_inline_in_notification);',
'',
'END;'))
,p_process_error_message=>'Error, no se pudo procesar la solicitud'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'denegar'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_process_success_message=>unistr('La solicitud de vacaciones fue denegada con \00E9xito')
);
end;
/
