,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT distinct e.id_empleado,  ',
'				e.cedula, ',
'				(e.nombre || '' '' || e.primer_apellido || '' '' || e.segundo_apellido) AS "Nombre Completo", ',
'				sv.fecha_inicio AS "Desde", ',
'				sv.fecha_fin AS "Hasta", ',
unistr('				sv.dias_vacaciones AS "Cantidad de D\00EDas",'),
'				dv.INICIO_PERIODO || '' - '' || dv.FIN_PERIODO AS PERIODO,',
'				sv.ESTADO_PROCESO,',
'				sv.ID_SOLICITUD_VACACION,',
'				sv.ID_VACACION_COLECTIVA,',
'				EIS.ULTIMA_ACREDITACION_VACACIONES,',
'				svl.ACREDITADAS_HABILES,',
'				svl.SALDO_HABIL,',
'				sv.NOMBRE_DEPENDENCIA,',
'				sv.ID_EMPLEADO_JEFE',
'FROM  empleados e,',
'	  solicitudes_vacaciones_legales sv,',
'	  DISTRIBUCION_DIAS_VACACIONES dv,',
'	  EMPLEADOS_INSTITUCION_SIRHP EIS,',
'	  SALDO_VACACIONES_LEGALES svl',
'where e.id_empleado = sv.id_empleado',
'   and sv.ID_SOLICITUD_VACACION = dv.ID_SOLICITUD_VACACION',
'   and e.id_empleado = svl.id_empleado',
'   and dv.INICIO_PERIODO = svl.INICIO_PERIODO',
'   and E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'--ORDER BY sv.fecha_inicio DESC;'))
