wwv_flow_api.create_page_validation(
 p_id=>wwv_flow_api.id(332410738896290712)
,p_validation_name=>'VAL_DIAS_NO_MAYOR_DIAS_SOL'
,p_validation_sequence=>90
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE ',
'V_DIAS_SOL_VACAS NUMBER;',
'BEGIN',
'',
'SELECT DIAS_VACACIONES',
'INTO V_DIAS_SOL_VACAS',
'FROM SOLICITUDES_VACACIONES_LEGALES ',
'WHERE ID_SOLICITUD_VACACION = :P4_ID_SOLICITUD_VACACION;',
'',
'IF :P4_CANTIDAD_DE_DIAS IS NULL THEN',
'    RETURN NULL;',
'END IF;',
'',
'IF V_DIAS_SOL_VACAS < :P4_CANTIDAD_DE_DIAS THEN',
unistr('    RETURN ''La cantidad neta de d\00EDas a devolver no puede ser mayor a los d\00EDas de la solicitud'';'),
'END IF;',
'',
'EXCEPTION ',
'    WHEN NO_DATA_FOUND THEN',
'        RETURN NULL;',
'    WHEN OTHERS THEN',
'        RETURN NULL;',
'END;'))
,p_validation_type=>'FUNC_BODY_RETURNING_ERR_TEXT'
,p_when_button_pressed=>wwv_flow_api.id(572551286054952816)
