,p_name=>'DAC_CALCULA_DESDE'
,p_event_sequence=>10
,p_triggering_element_type=>'ITEM'
,p_triggering_element=>'P4_DESDE'
,p_bind_type=>'bind'
,p_bind_event_type=>'change'
);
wwv_flow_api.create_page_da_action(
 p_id=>wwv_flow_api.id(572560488276952784)
,p_event_id=>wwv_flow_api.id(572560010024952785)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE ',
'    vcantidaddias number(10) := 0;',
'    vcantidaddiasferiados number(10) := 0;',
'    vfecha_inicio varchar2(20);',
'    vfecha_fin varchar2(20);',
'',
'BEGIN',
'    ',
'IF :P4_SKIP_RECALC = 1 THEN',
'    RETURN;',
'END IF;',
'    ',
'    IF :P4_DESDE IS NOT NULL THEN',
'        IF :P4_HASTA IS NOT NULL THEN',
'        ',
'            vfecha_inicio := To_DATE(:P4_DESDE, ''dd/mm/yy'');',
'            vfecha_fin := To_DATE(:P4_HASTA, ''dd/mm/yy'');',
'            vcantidaddias := PKG_UTILIDADES.f_dias_laborables(vfecha_inicio, vfecha_fin);',
'            vcantidaddiasferiados := PKG_VACACIONES.f_cant_dias_feriados(vfecha_inicio, vfecha_fin);',
'                        ',
'             IF :P4_DEVOLVER_TODO = 1 THEN',
'                             ',
