wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(572555420405952799)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_SOLICITAR_DEVOLUCION'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    ',
'    vId_Jefe number := 0;',
'    vMedioDia varchar(100);',
'    vmedioD_manana number := 0;',
'    vmedioD_tarde number := 0;',
'    vNombreJefe VARCHAR2(255);',
'    vid_estado NUMBER;',
'    vconsecutivo NUMBER;',
'    v_cursor SYS_REFCURSOR;',
'    vnombre_empleado VARCHAR2(255);',
'    vcorreo_destino_emp VARCHAR2(255);',
'    vcorreo_destino_jefe VARCHAR2(255);',
'    v_id_emp_solicita NUMBER;',
'    v_nombre_emp_solicita VARCHAR2(255);',
'    v_text_cant_dias VARCHAR2(255);',
'    v_tipo_solciitud VARCHAR2(3):= ''DV'';',
'    v_dias_a_devolver NUMBER;',
'',
'BEGIN',
'    ',
unistr('-- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'    CASE :ID_MODULO_SIS',
'        WHEN 1 THEN ',
'            vid_estado := 13;',
'        WHEN 3 THEN ',
'            vid_estado := 7;',
'    ELSE ',
'        vid_estado := NULL;',
'    END CASE;',
'   ',
'   IF :P4_MEDIO_DIA = 1 THEN',
'	    IF :P6_TIPO_MEDIO_DIA = 0 THEN',
unistr('            vMedioDia := ''MA\00D1ANA'';'),
'			vmedioD_manana := 1;',
'		ELSE',
'            vMedioDia := ''TARDE'';',
'			vmedioD_tarde := 1;',
'        END IF;',
'	END IF;',
'',
'   ',
'    --v_tipo_solciitud := PKG_DEVOLUCION.f_get_tipo_soli_vaca(:P4_ID_SOLICITUD_VACACION);',
'',
'   /* IF :P4_DEVOLVER_TODO = 1 THEN',
'        v_dias_a_devolver := PKG_DEVOLUCION.f_get_dias_vaca_solicitud(:P4_ID_SOLICITUD_VACACION);',
'    ELSE',
'        v_dias_a_devolver:= :P4_CANTIDAD_DE_DIAS;',
'    END IF;*/',
'',
'    v_dias_a_devolver:= :P4_CANTIDAD_DE_DIAS;',
'',
'    vconsecutivo := PKG_GESTION.f_solicitud_vacaciones(:P4_ID_EMPLEADO, ',
'                                                       :P4_DESDE,',
'                                                       :P4_HASTA,',
'                                                       vmedioD_manana,',
'                                                       vmedioD_tarde, ',
'                                                       v_dias_a_devolver,',
'                                                       0,',
'                                                       NULL,',
'                                                       vid_estado,',
'                                                       v_tipo_solciitud,',
'                                                       :APP_USER, ',
'                                                       v_tipo_solciitud,',
'                                                      :P4_ID_SOLICITUD_VACACION,',
'                                                      :P4_MOTIVO);',
'                              ',
'    IF vconsecutivo IS NOT NULL THEN',
'        ',
'        vnombre_empleado := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(:P4_ID_EMPLEADO);',
'        ',
unistr('        v_cursor := PKG_PLANI.f_obtener_jefe_x_cod_sirh(:P4_ID_EMPLEADO); -- Llamada a la funci\00F3n'),
'        FETCH v_cursor INTO vId_Jefe, vNombreJefe;',
'        CLOSE v_cursor;',
'',
'        -- Obtener el correo del funcionario y jefe',
'        vcorreo_destino_emp := PKG_PLANI.f_get_correo_emp_x_cod_sirh(:P4_ID_EMPLEADO);',
'        vcorreo_destino_jefe := PKG_PLANI.f_get_correo_emp_x_cod_sirh(vId_Jefe);',
'        ',
'        v_id_emp_solicita := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'        v_nombre_emp_solicita := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_id_emp_solicita);',
'        ',
'        --v_text_cant_dias := TO_CHAR(v_dias_a_devolver);    ',
'    ',
'        --v_text_cant_dias :=   TO_CHAR(v_dias_a_devolver, ''FM9990D99'', ''NLS_NUMERIC_CHARACTERS=.,'');',
'        ',
'        v_text_cant_dias :=',
'            TO_CHAR(',
'            v_dias_a_devolver,',
'            ''TM9'',',
'            ''NLS_NUMERIC_CHARACTERS=.,''',
'        );',
'',
'    ',
'        IF v_dias_a_devolver < 1 THEN',
'            v_text_cant_dias := ''0.5'';',
'        END IF;',
'',
unistr('        -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'        CASE :ID_MODULO_SIS',
'            WHEN 1 THEN ',
'                PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_emp,',
'                   p_cc_in => vcorreo_destino_jefe,',
'                   p_id_mensaje => 8,',
'                   p_parametros => ''NOMBRE='' || vnombre_empleado || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P4_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P4_PERIODO_HABIL ||',
'                                   '',FECHA_INICIAL='' || :P4_DESDE || ',
'                                   '',FECHA_FINAL='' || :P4_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                                   '',MOTIVO='' || :P4_MOTIVO ||',
'                                   '',ID_EMPLEADO_SOLICITA='' || v_nombre_emp_solicita',
'               );',
'            WHEN 3 THEN',
'                PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_jefe,',
'                   p_cc_in => NULL,',
'                   p_id_mensaje => 7,',
'                   p_parametros => ''NOMBRE='' || vnombre_empleado || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P4_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P4_PERIODO_HABIL ||',
'                                   '',FECHA_INICIAL='' || :P4_DESDE || ',
'                                   '',FECHA_FINAL='' || :P4_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                                   '',MOTIVO='' || :P4_MOTIVO',
'               );',
'            ELSE ',
'                vcorreo_destino_emp := NULL;',
'                vcorreo_destino_jefe := NULL;',
'            END CASE;',
'    END IF;',
'    ',
'     EXCEPTION',
'		WHEN OTHERS THEN',
unistr('        apex_error.add_error (p_message => ''Error al solicitar la devoluci\00F3n de las vacaciones: ''|| SQLERRM,'),
'                              p_display_location => apex_error.c_inline_in_notification);',
'END;'))
,p_process_error_message=>unistr('Error al solicitar la devoluci\00F3n de las vacaciones')
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(572551286054952816)
,p_process_success_message=>unistr('Solicitud de devoluci\00F3n enviada con \00E9xito')
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(572634424500102479)
,p_process_sequence=>10
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_CARGAR_DATOS_EMPLEADO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_cursor SYS_REFCURSOR;',
'    vIdEmpleado NUMBER;',
'	vCedula VARCHAR2(100);',
'	vNombre  VARCHAR2 (100);',
'	vApellido1 VARCHAR2(100);',
'	vApellido2 VARCHAR2(100);',
'    vNombreJefe VARCHAR2(100);',
'	vId_Jefe NUMBER; ',
'        ',
'    CURSOR C_DATOS_EMPLEADO IS',
'        ',
'    SELECT',
'            E.ID_EMPLEADO,',
'            E.CEDULA,',
'            E.NOMBRE,',
'            E.PRIMER_APELLIDO,',
'            E.SEGUNDO_APELLIDO',
'    FROM EMPLEADOS E',
'    INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'    INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'    INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'    WHERE E.ID_EMPLEADO = :P4_ID_EMPLEADO --:ID_EMPLEADO_GLOBAL',
'    AND MP.indicador_vigente = 1;',
'        ',
'BEGIN',
'        ',
'	OPEN C_DATOS_EMPLEADO;',
'    FETCH C_DATOS_EMPLEADO INTO vIdEmpleado, vCedula, vNombre, vApellido1, vApellido2;',
'    CLOSE C_DATOS_EMPLEADO;',
'    ',
unistr('    v_cursor := PKG_PLANI.f_obtener_jefe_x_cod_sirh(vIdEmpleado); -- Llamada a la funci\00F3n'),
'    FETCH v_cursor INTO vId_Jefe, vNombreJefe;',
'    CLOSE v_cursor;',
'    ',
'	:P4_CEDULA := vCedula;   ',
'    :P4_NOMBRE := vNombre;',
'	:P4_PRIMER_APELLIDO := vApellido1;',
'	:P4_SEGUNDO_APELLIDO := vApellido2;',
'',
'    :P4_ID_JEFE := vId_Jefe;',
'	:P4_NOMBRE_JEFE := vNombreJefe;',
'	:P4_PERIODO_HABIL := PKG_UTILIDADES.f_retorna_periodo_habil(vIdEmpleado); ',
'    :P4_SALDO_HABIL :=  to_char(PKG_UTILIDADES.f_retorna_saldo_habil(vIdEmpleado), ''990D0''); ',
'END;'))
,p_process_error_message=>'Error al cargar los datos del empleado'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(572555903065952793)
,p_process_sequence=>20
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_CARGAR_OTROS_DATOS'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    vcantidaddiasferiados number(10) := 0;',
'    vfecha_inicio varchar2(20);',
'	vfecha_fin varchar2(20);',
'',
'BEGIN',
'',
'    IF :P4_ID_SOLICITUD_VACACION IS NOT NULL THEN',
'        ',
'        vfecha_inicio := To_DATE(:P4_DESDE, ''dd/mm/yy'');',
'        vfecha_fin := To_DATE(:P4_HASTA, ''dd/mm/yy'');',
'        ',
'        IF :P4_CANTIDAD_DE_DIAS < 1 THEN',
'            :P4_CANTIDAD_DE_DIAS := ''0,5'';',
'        END IF;',
'        ',
'        vcantidaddiasferiados := PKG_VACACIONES.f_cant_dias_feriados(vfecha_inicio, vfecha_fin);',
'        :P4_CANTIDAD_DE_DIAS_FERIADOS := vcantidaddiasferiados;',
'        ',
'         :P4_CANTIDAD_DE_DIAS :=  to_char(PKG_DEVOLUCION.f_get_dias_vaca_solicitud(:P4_ID_SOLICITUD_VACACION), ''990D0''); ',
'        ',
'    END IF;',
'END;',
''))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
end;
