 p_id=>wwv_flow_api.id(325344946818378006)
,p_name=>'DAC_VALIDAR_SOLICITUD'
,p_event_sequence=>10
,p_bind_type=>'bind'
,p_bind_event_type=>'ready'
);
wwv_flow_api.create_page_da_action(
 p_id=>wwv_flow_api.id(325345062588378007)
,p_event_id=>wwv_flow_api.id(325344946818378006)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_current_year   NUMBER := TO_NUMBER(TO_CHAR(SYSDATE, ''YYYY''));',
'    v_current_start  NUMBER;',
'    v_count_future   NUMBER := 0;',
'    v_count_saldo_future NUMBER := 0;',
'    v_count_saldo_past   NUMBER := 0;',
'BEGIN',
'    :P5_MSJ_NO_PROPOCIONALES := NULL;',
'',
'    --Obtener el inicio del periodo actual del empleado',
'    SELECT MIN(INICIO_PERIODO)',
'      INTO v_current_start',
'      FROM SALDO_VACACIONES_LEGALES',
'     WHERE ID_EMPLEADO = :P5_ID_EMPLEADO',
'       AND v_current_year BETWEEN INICIO_PERIODO AND FIN_PERIODO;',
'',
'    --Si no hay periodo actual, asumimos que no existen',
'    IF v_current_start IS NULL THEN',
'        v_count_future := 0;',
'    ELSE',
'        --Contar periodos desde el actual hacia adelante',
'        SELECT COUNT(*)',
'          INTO v_count_future',
'          FROM SALDO_VACACIONES_LEGALES',
'         WHERE ID_EMPLEADO = :P5_ID_EMPLEADO',
'           AND INICIO_PERIODO >= v_current_start;',
'        ',
'        --Contar periodos futuros con saldo > 0',
'        SELECT COUNT(*)',
'          INTO v_count_saldo_future',
'          FROM SALDO_VACACIONES_LEGALES',
'         WHERE ID_EMPLEADO = :P5_ID_EMPLEADO',
'           AND INICIO_PERIODO >= v_current_start',
'           AND NVL(SALDO_HABIL, 0) > 0;',
'           ',
'        --Contar periodos anteriores con saldo > 0',
'        SELECT COUNT(*)',
'          INTO v_count_saldo_past',
'          FROM SALDO_VACACIONES_LEGALES',
'         WHERE ID_EMPLEADO = :P5_ID_EMPLEADO',
'           AND INICIO_PERIODO < v_current_start',
'           AND NVL(SALDO_HABIL, 0) > 0;',
'    END IF;',
unistr('    --Asignar bandera para mostrar/ocultar el bot\00F3n'),
'    :P5_FLAG_HIDE_SOLI_BUTTON := ',
'        CASE ',
'            WHEN v_count_future > 2 ',
'                 AND v_count_saldo_future = 0 ',
'                 AND v_count_saldo_past = 0 THEN ''Y''',
'            ELSE ''N''',
'        END;',
'    -- Mensaje al usuario',
'    IF v_count_future > 2 AND v_count_saldo_future = 0 AND v_count_saldo_past = 0 THEN',
'        :P5_MSJ_NO_PROPOCIONALES :=',
unistr('            ''Estimada persona funcionaria, ya no es posible solicitar vacaciones proporcionales porque posee m\00E1s de 2 per\00EDodos a futuro y no cuenta con saldos disponibles en per\00EDodos anteriores o actuales.'';'),
'    END IF;',
'END;'))
,p_attribute_02=>'P5_ID_EMPLEADO'
,p_attribute_03=>'P5_FLAG_HIDE_SOLI_BUTTON,P5_MSJ_NO_PROPOCIONALES'
,p_attribute_04=>'N'
,p_wait_for_result=>'Y'
);
wwv_flow_api.create_page_da_action(
 p_id=>wwv_flow_api.id(325345254975378009)
,p_event_id=>wwv_flow_api.id(325344946818378006)
,p_event_result=>'TRUE'
,p_action_sequence=>20
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'if ($v("P5_FLAG_HIDE_SOLI_BUTTON") === "Y") {',
'    $("#NUEVA_SOLICITUD_PROPORCIONALES").hide();',
'} else {',
'    $("#NUEVA_SOLICITUD_PROPORCIONALES").show();',
'}',
'',
'',
'let msg = $v("P5_MSJ_NO_PROPOCIONALES");',
'if (msg) {',
'    alert(msg);',
'    $s("P5_MSJ_NO_PROPOCIONALES", "");',
'}',
''))
);
wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(569987913938676529)
,p_process_sequence=>10
,p_process_point=>'AFTER_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_CARGA_DATOS_EMPLEADO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    vIdEmpleado NUMBER;',
'	vCedula VARCHAR2(100);',
'	vNombre  VARCHAR2 (100);',
'	vApellido1 VARCHAR2(100);',
'	vApellido2 VARCHAR2(100);',
'	vFechaNac DATE;',
'	vTelefono VARCHAR2(20);',
'	vEmail VARCHAR2(100);',
'	vFechaIngAdmPubli DATE;',
'	vIdIncap_Emple NUMBER;',
'	vIdPuesto VARCHAR2(50);',
'	vDepartamento VARCHAR2(100);',
'	vUltFechaAcred DATE;',
'    v_count_saldo NUMBER := 0;       ',
'           ',
'    CURSOR C_DATOS_EMPLEADO IS',
'        ',
'    SELECT',
'            E.ID_EMPLEADO,',
'            E.CEDULA,',
'            E.NOMBRE,',
'            E.PRIMER_APELLIDO,',
'            E.SEGUNDO_APELLIDO,',
'            E.FECHA_NACIMIENTO,',
'            E.TELEFONO_OFICINA,',
'            E.EMAIL,',
'            E.FECHA_INGRESO_ADMIN_PUBLICA,',
'            DM.CODIGO_PRESUPUESTARIO AS ID_PUESTO,',
'            UPPER(DM.NOMBRE_DEPENDENCIA) AS DEPARTAMENTO,',
'            EIS.ULTIMA_ACREDITACION_VACACIONES AS FVAC',
'    FROM EMPLEADOS E',
'    INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'    INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'    INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'    WHERE E.ID_EMPLEADO = :P5_ID_EMPLEADO--:ID_EMPLEADO_GLOBAL',
'    AND MP.indicador_vigente = 1;',
'        ',
'BEGIN',
'        ',
'	OPEN C_DATOS_EMPLEADO;',
'    FETCH C_DATOS_EMPLEADO ',
'    INTO ',
'        vIdEmpleado, ',
'        vCedula, ',
'        vNombre, ',
'        vApellido1, ',
'        vApellido2, ',
'		vFechaNac, ',
'        vTelefono, ',
'        vEmail, ',
'        vFechaIngAdmPubli, ',
'	    vIdPuesto, ',
'        vDepartamento, ',
'        vUltFechaAcred;',
'    CLOSE C_DATOS_EMPLEADO;',
'    ',
'	:P5_ID_EMPLEADO := vIdEmpleado;',
'	:P5_CEDULA := vCedula;   ',
'    :P5_NOMBRE := vNombre;',
'	:P5_PRIMER_APELLIDO := vApellido1;',
'	:P5_SEGUNDO_APELLIDO := vApellido2;',
'    :P5_FECHA_NACIMIENTO := vFechaNac;',
'	:P5_TELEFONO_OFICINA:= vTelefono;',
'    :P5_EMAIL := vEmail;',
'	:P5_ID_PUESTO := vIdPuesto;',
'	:P5_DEPARTAMENTO := vDepartamento;',
'    :P5_FECHA_INGRESO_ADMIN_PUBLICA := vFechaIngAdmPubli;',
'    :P5_FVAC := vUltFechaAcred;',
'    ',
'    SELECT COUNT(*)',
'        INTO v_count_saldo',
'        FROM SALDO_VACACIONES_LEGALES',
'        WHERE ID_EMPLEADO = vIdEmpleado',
'          --AND INICIO_PERIODO >= v_current_start',
'          AND NVL(SALDO_HABIL,0) > 0;',
'          ',
'    IF v_count_saldo > 0 THEN      ',
'	    :P5_PERIODO_HABIL := PKG_UTILIDADES.f_retorna_periodo_habil(vIdEmpleado); ',
'        :P5_SALDO_HABIL :=  to_char(PKG_UTILIDADES.f_retorna_saldo_habil(vIdEmpleado), ''990D0'');    ',
'    ELSE',
'        :P5_PERIODO_HABIL := PKG_UTILIDADES.f_get_max_periodo_empleado(vIdEmpleado); ',
'        :P5_SALDO_HABIL :=  to_char(PKG_UTILIDADES.f_get_saldo_max_periodo_emp(vIdEmpleado), ''990D0''); ',
'    END IF;',
'END;'))
,p_process_error_message=>'Error al cargar los datos del empleado'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
end;
/
