wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(570792588635673600)
,p_process_sequence=>20
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_CREAR_SOLICITUD'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'	vmedioD_manana NUMBER := 0;',
'	vmedioD_tarde NUMBER := 0;',
'    vcantidad_dias NUMBER (5, 1);',
'    vid_estado NUMBER;',
'    vcorreo_destino_emp VARCHAR2(255);',
'    vcorreo_destino_jefe VARCHAR2(255);',
'    v_id_emp_solicita VARCHAR2(255);',
'    v_nombre_emp_solicita VARCHAR2(255);',
'    v_nombre_emp VARCHAR(255);',
'    v_text_cant_dias VARCHAR2(50);',
'    ',
'BEGIN',
unistr('-- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'  CASE :ID_MODULO_SIS',
'    WHEN 1 THEN ',
'        vid_estado := 17;',
'    WHEN 3 THEN ',
'        vid_estado := 6;',
'    ELSE ',
'        vid_estado := NULL;',
'  END CASE;',
'    ',
'    vcantidad_dias := TO_NUMBER(:P6_CANTIDAD_DE_DIAS);',
'    ',
'    IF :P6_MEDIO_DIA = 1 THEN',
'        IF :P6_TIPO_MEDIO_DIA = 0 THEN',
'            vmedioD_manana := 1;',
'        ELSE',
'            vmedioD_tarde := 1;',
'        END IF;',
'        vcantidad_dias := 0.5;',
'    END IF;',
'    ',
'	:P6_ID_SOLICITUD_VACACION := PKG_GESTION.f_solicitud_vacaciones(:P6_ID_EMPLEADO, ',
'                                                                    :P6_DESDE, ',
'                                                                    :P6_HASTA, ',
'                                                                    vmedioD_manana, ',
'                                                                    vmedioD_tarde,',
'                                                                    vcantidad_dias, ',
'                                                                    NULL, ',
'                                                                    NULL, ',
'                                                                    vid_estado, ',
'                                                                    ''EA'', ',
'                                                                    :APP_USER, ',
'                                                                    ''VN'',',
'                                                                    NULL);',
'    ',
'    IF :P6_ID_SOLICITUD_VACACION IS NOT NULL THEN',
'    ',
'        vcorreo_destino_emp := PKG_PLANI.f_get_correo_emp_x_cod_sirh(:P6_ID_EMPLEADO);',
'        vcorreo_destino_jefe := PKG_PLANI.f_get_correo_emp_x_cod_sirh(:P6_ID_JEFE);',
'        v_id_emp_solicita := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'        v_nombre_emp_solicita := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_id_emp_solicita);',
'        ',
'        v_nombre_emp := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(:P6_ID_EMPLEADO);',
'        ',
'        v_text_cant_dias := TO_CHAR(vcantidad_dias);',
'        ',
'        IF :P6_MEDIO_DIA = 1 THEN',
'            IF vmedioD_manana = 1 THEN',
unistr('                 v_text_cant_dias := ''0.5'' || '' - ma\00F1ana'';'),
'            ELSE',
'                v_text_cant_dias := ''0.5'' || '' - tarde'';',
'            END IF;',
'        END IF;',
'',
unistr('        -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'        CASE :ID_MODULO_SIS',
'            WHEN 1 THEN ',
'                PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_emp,',
'                   p_cc_in => vcorreo_destino_jefe,',
'                   p_id_mensaje => 2,',
'                   p_parametros => ''NOMBRE='' || v_nombre_emp || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P6_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P6_PERIODO_HABIL ||',
'                                   '',FECHA_INICIAL='' || :P6_DESDE || ',
'                                   '',FECHA_FINAL='' || :P6_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                                   '',ID_EMPLEADO_SOLICITA='' || v_nombre_emp_solicita',
'               );',
'            WHEN 3 THEN',
'               PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_jefe,',
'                   p_cc_in => NULL,',
'                   p_id_mensaje => 1,',
'                   p_parametros => ''NOMBRE='' || v_nombre_emp_solicita || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P6_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P6_PERIODO_HABIL ||',
'                                   '',FECHA_INICIAL='' || :P6_DESDE || ',
'                                   '',FECHA_FINAL='' || :P6_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias',
'               );',
'            ELSE ',
'                vcorreo_destino_emp := NULL;',
'                vcorreo_destino_jefe := NULL;',
'      END CASE;',
'    END IF;',
'    ',
'    EXCEPTION',
'    WHEN OTHERS THEN',
unistr('		apex_error.add_error (p_message => ''Error al tramitar la boleta de vacaci\00F3n: ''|| SQLERRM,'),
'                              p_display_location => apex_error.c_inline_in_notification);',
'',
'END;'))
,p_process_error_message=>unistr('Error, no se pud\00F3 generar la solicitud')
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(570787785852673604)
,p_process_success_message=>unistr('Solicitud de vacaciones enviada con \00E9xito')
);
end;
/
