,p_process_sequence=>20
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_CARGA_DATOS'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_cursor SYS_REFCURSOR;',
'    vId_Jefe NUMBER; ',
'	vNombreJefe VARCHAR2(100);',
'',
'BEGIN',
'    IF :P6_ID_EMPLEADO IS NOT NULL THEN',
'    ',
unistr('        v_cursor := PKG_PLANI.f_obtener_jefe_x_cod_sirh(:P6_ID_EMPLEADO); -- Llamada a la funci\00F3n'),
'        FETCH v_cursor INTO vId_Jefe, vNombreJefe;',
'        CLOSE v_cursor;',
'',
'        :P6_ID_JEFE := vId_Jefe;',
'		:P6_NOMBRE_JEFE := vNombreJefe;',
'        :P6_DESDE := NULL;',
'        :P6_HASTA := NULL;',
'        :P6_MEDIO_DIA := 0;',
'        :P6_CANTIDAD_DE_DIAS := 0;',
'        :P6_CANTIDAD_DE_DIAS_FERIADOS := 0;',
'        :P6_SALDO_HABIL :=  TO_CHAR(PKG_UTILIDADES.f_retorna_saldo_habil(:P6_ID_EMPLEADO), ''990D0''); ',
'        ',
'	END IF;',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
);
null;
end;
