wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(850229994668983162)
,p_plug_name=>unistr('Datos de la Solicitud de Devoluci\00F3n de Vacaciones')
,p_region_template_options=>'#DEFAULT#:t-Region--accent9:t-Region--stacked:t-Region--scrollBody'
,p_plug_template=>wwv_flow_api.id(480172181371480527)
,p_plug_display_sequence=>10
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'	e.id_empleado, ',
'	e.cedula, (e.nombre|| '' '' || e.primer_apellido || '' '' || e.segundo_apellido) as "Nombre Completo", ',
'	CAST(sv.fecha_inicio AS DATE) as "Desde", ',
'	CAST(sv.fecha_fin AS DATE) AS "Hasta", ',
'    sv.dias_vacaciones,',
'	dv.INICIO_PERIODO||'' - ''|| dv.FIN_PERIODO PERIODO, ',
'	sv.ID_SOLICITUD_VACACION, ',
'	sv.ID_VACACION_COLECTIVA, ',
'	sv.ID_ESTADO,',
'	sv.FECHA_REGISTRO,',
'	dv.INICIO_PERIODO,',
'    UPPER(DBMS_LOB.SUBSTR(sv.MOTIVO, 1000, 1)) AS "Motivo"',
'FROM empleados e',
'	INNER JOIN solicitudes_vacaciones_legales sv ON e.id_empleado = sv.id_empleado',
'	INNER JOIN DISTRIBUCION_DIAS_VACACIONES dv ON sv.ID_SOLICITUD_DEVOLUCION_VACAC = dv.ID_SOLICITUD_VACACION',
'WHERE',
'	sv.ID_SOLICITUD_VACACION = :P7_ID_SOLICITUD_VACACION'))
,p_is_editable=>true
,p_edit_operations=>'i:u:d'
,p_lost_update_check_type=>'VALUES'
,p_plug_source_type=>'NATIVE_FORM'
,p_ajax_items_to_submit=>'P7_ID_SOLICITUD_VACACION'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
);
