wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(573548616439253878)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_APROBAR_DEV_VACACIONES'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'',
'    v_cursor SYS_REFCURSOR;',
'    v_id_empleado_aprueba NUMBER;',
'    vid_estado NUMBER;',
'    vNombreJefe VARCHAR2(100);',
'	vId_Jefe NUMBER; ',
'    vnombre_empleado VARCHAR2(255);',
'    vcorreo_destino_emp VARCHAR2(255);',
'    vcorreo_destino_jefe VARCHAR2(255);',
'    v_nombre_empleado_aprueba VARCHAR(255);',
'    v_resultado NUMBER;',
'    v_text_cant_dias VARCHAR2(50);',
'    v_tipo_solicitud CHAR(5);',
'    v_cod_estado_solicitud CHAR(2);',
'',
'BEGIN',
'',
unistr('-- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'    CASE :ID_MODULO_SIS',
'        WHEN 1 THEN ',
'            vid_estado := 14;',
'        WHEN 2 THEN ',
'            vid_estado := 8;',
'    ELSE ',
'        vid_estado := NULL;',
'    END CASE;',
'    ',
'    v_id_empleado_aprueba := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'    v_nombre_empleado_aprueba := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_id_empleado_aprueba);  ',
'    v_tipo_solicitud := PKG_DEVOLUCION.f_get_tipo_soli_vaca(:P7_ID_SOLICITUD_VACACION);',
'    v_cod_estado_solicitud:= PKG_DEVOLUCION.f_get_cod_estado_soli_vaca(:P7_ID_SOLICITUD_VACACION);',
'        ',
'    IF v_cod_estado_solicitud != ''DA'' THEN',
'    ',
'        PKG_DEVOLUCION.sp_devolucion_vacaciones(',
'            PId_Empleado => :P7_ID_EMPLEADO,   ',
'            PDias => :P7_DIAS_VACACIONES,      ',
'            PPeriodo_Inicio => :P7_INICIO_PERIODO,      ',
'            PConsecutivo => :P7_ID_SOLICITUD_VACACION,',
'            PJustificacion => :NULL,',
'            PId_Modificador => v_id_empleado_aprueba,',
'            Pid_estado => vid_estado,',
'            pestado => ''DA'',',
'            pTipoSolicitud => v_tipo_solicitud,',
'            POUT_Resultado => v_resultado',
'        );',
'',
'        IF v_resultado = 1 THEN',
'',
unistr('            v_cursor := PKG_PLANI.f_obtener_jefe_x_cod_sirh(:P7_ID_EMPLEADO); -- Llamada a la funci\00F3n'),
'            FETCH v_cursor INTO vId_Jefe, vNombreJefe;',
'            CLOSE v_cursor;',
'',
'            -- Obtener el correo del funcionario y jefe',
'            vcorreo_destino_emp := PKG_PLANI.f_get_correo_emp_x_cod_sirh(:P7_ID_EMPLEADO);',
'            vcorreo_destino_jefe := PKG_PLANI.f_get_correo_emp_x_cod_sirh(vId_Jefe);',
'',
'            --v_text_cant_dias := TO_CHAR(:P7_DIAS_VACACIONES);    ',
'',
'',
'            v_text_cant_dias :=',
'            TO_CHAR(',
'            :P7_DIAS_VACACIONES,',
'            ''TM9'',',
'            ''NLS_NUMERIC_CHARACTERS=.,''',
'                );',
'',
'            IF :P7_DIAS_VACACIONES < 1 THEN',
'                        v_text_cant_dias := ''0.5'';',
'            END IF;',
'',
'            --IF v_text_cant_dias < 1 THEN',
'              -- v_text_cant_dias := ''0.5'';',
'            --END IF;',
'',
'',
unistr('          -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'          CASE :ID_MODULO_SIS',
'            WHEN 1 THEN ',
'                PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_emp,',
'                   p_cc_in => vcorreo_destino_jefe,',
'                   p_id_mensaje => 9,',
'                   p_parametros => ''NOMBRE='' || :P7_NOMBRE_COMPLETO || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P7_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P7_PERIODO ||',
'                                   '',FECHA_INICIAL='' || :P7_DESDE || ',
'                                   '',FECHA_FINAL='' || :P7_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                                   '',ID_EMPLEADO_APRUEBA='' || v_nombre_empleado_aprueba',
'               );',
'            WHEN 2 THEN',
'               PKG_CORREOS.sp_enviar_correo_html(',
'                   p_destinatario_in => vcorreo_destino_emp,',
'                   p_cc_in => NULL,',
'                   p_id_mensaje => 9,',
'                   p_parametros => ''NOMBRE='' || :P7_NOMBRE_COMPLETO || ',
'                                   '',ID_SOLICITUD_VACACION='' || :P7_ID_SOLICITUD_VACACION ||',
'                                   '',PERIODO='' || :P7_PERIODO ||',
'                                   '',FECHA_INICIAL='' || :P7_DESDE || ',
'                                   '',FECHA_FINAL='' || :P7_HASTA || ',
'                                   '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                                   '',ID_EMPLEADO_APRUEBA='' || v_nombre_empleado_aprueba',
'               );',
'            ELSE ',
'                vcorreo_destino_emp := NULL;',
'                vcorreo_destino_jefe := NULL;',
'          END CASE;',
'        END IF;',
'    ',
'    ELSE',
unistr('     apex_error.add_error (p_message => ''La devoluci\00F3n ya hab\00EDa sido aprobada previamente por favor revisar.'','),
'                                 p_display_location => apex_error.c_inline_in_notification);  ',
'    END IF;',
'    EXCEPTION',
'       WHEN OTHERS THEN',
unistr('	       apex_error.add_error (p_message => ''Error al enviar la notificaci\00F3n: ''|| SQLERRM,'),
'                                 p_display_location => apex_error.c_inline_in_notification);',
'END;'))
,p_process_error_message=>'Error, no se pudo procesar la solicitud'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'aprobar'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_process_success_message=>unistr('La solicitud de devoluci\00F3n de vacaciones fue aprobada con \00E9xito')
);
