,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'  SELECT DISTINCT ',
'            E.ID_EMPLEADO,',
'            E.CEDULA,',
'            E.NOMBRE || '' '' || E.PRIMER_APELLIDO || '' '' || E.SEGUNDO_APELLIDO AS NOMBRE,',
'            E.FECHA_NACIMIENTO,',
'            E.TELEFONO_OFICINA,',
'            LOWER(E.EMAIL) AS EMAIL,',
'            UPPER(DM.NOMBRE_DEPENDENCIA) AS DEPARTAMENTO',
'    FROM EMPLEADOS E',
'    INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'    INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'    INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'    INNER JOIN EMPLEADOS@CONSULTA_ICT EMP ON E.ID_EMPLEADO = EMP.CODIGO_EMPLEADO_SIRH',
'    INNER JOIN USUARIOS@CONSULTA_ICT USU ON EMP.CODIGO_EMPLEADO = USU.CODIGO_EMPLEADO',
'    WHERE MP.INDICADOR_VIGENTE = 1 AND EMP.CODIGO_ESTADO = 1 AND USU.ESTADO = 1;'))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>unistr('Form: Gesti\00F3n de Vacaciones Por Empleado')
);
