'DECLARE ',
'	vcantidaddias number(10) := 0;',
'    vcantidaddiasferiados number(10) := 0;',
'	vfecha_actual varchar2(20);',
'	vfecha_inicio varchar2(20);',
'	vfecha_fin varchar2(20);',
'',
'BEGIN',
'    IF :P12_FECHA_INICIO IS NOT NULL THEN',
'        IF :P12_FECHA_FIN IS NOT NULL THEN',
'			vfecha_inicio := To_DATE(:P12_FECHA_INICIO, ''dd/mm/yy'');',
'            vfecha_fin := To_DATE(:P12_FECHA_FIN, ''dd/mm/yy'');',
'            vcantidaddias := PKG_UTILIDADES.f_dias_laborables(vfecha_inicio, vfecha_fin);',
'            vcantidaddiasferiados := PKG_VACACIONES.f_cant_dias_feriados(vfecha_inicio, vfecha_fin);',
'            :P12_CANTIDAD_DE_DIAS := vcantidaddias - vcantidaddiasferiados;',
'            :P12_CANTIDAD_DE_DIAS_FERIADOS := vcantidaddiasferiados;',
'        END IF;',
'    END IF;',
'END;'))
,p_attribute_02=>'P12_FECHA_INICIO,P12_FECHA_FIN,P12_CANTIDAD_DE_DIAS'
,p_attribute_03=>'P12_CANTIDAD_DE_DIAS,P12_CANTIDAD_DE_DIAS_FERIADOS'
