wwv_flow_api.create_page_process(
 p_id=>wwv_flow_api.id(576500788273901209)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_PROCESAR_VACACION_COLECTIVA'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    vcantidad_dias NUMBER (5, 1);',
'    vdias_feriados NUMBER (5,1);',
'    vId_Modificador number := 0;',
'BEGIN',
'    ',
'    vcantidad_dias := TO_NUMBER(:P12_CANTIDAD_DE_DIAS);',
'    vdias_feriados := TO_NUMBER(:P12_CANTIDAD_DE_DIAS_FERIADOS);',
'    vId_Modificador := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'    ',
'	IF :P12_ID_VACACION_COLECTIVA IS NULL THEN',
'	   :P12_ID_VACACION_COLECTIVA := PKG_COLECTIVAS.f_obtener_vacacion_colectiva (NULL, ',
'                                                                        :P12_FECHA_INICIO,',
'                                                                        :P12_FECHA_FIN, ',
'                                                                        ''A'', ',
'                                                                        UPPER(:P12_MOTIVO), ',
'                                                                        vId_Modificador, ',
'                                                                        vcantidad_dias, ',
'                                                                        vdias_feriados);',
'    ELSE    ',
'        UPDATE VACACIONES_COLECTIVAS',
'        SET MOTIVO = UPPER(:P12_MOTIVO)',
'        WHERE ID_VACACION_COLECTIVA = :P12_ID_VACACION_COLECTIVA;',
'    END IF;',
'     ',
'    EXCEPTION',
'    WHEN OTHERS THEN',
unistr('		apex_error.add_error (p_message => ''Error al tramitar la vacaci\00F3n colectiva: ''|| SQLERRM,'),
'                              p_display_location => apex_error.c_inline_in_notification);',
'',
'END;'))
,p_process_error_message=>'Error al procesar la solicitud'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when=>'procesar-vacacion-colectiva'
,p_process_when_type=>'REQUEST_EQUALS_CONDITION'
,p_process_success_message=>unistr('La vacaci\00F3n colectiva se proces\00F3 correctamente')
);
