,p_action_sequence=>40
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_id_sol NUMBER;',
'    v_nom_sol VARCHAR2(255);',
'    v_cur SYS_REFCURSOR;',
'    vNomJefe VARCHAR2(100);',
'    vIdJefe NUMBER;',
'    vnom_emp VARCHAR2(255);',
'    vmail_emp VARCHAR2(255);',
'    vmail_jefe VARCHAR2(255);',
'    v_emps VARCHAR2(4000);',
'    v_emp_id NUMBER;',
'    v_emps_tab apex_application_global.vc_arr2;',
'    vcant_dias NUMBER(5,1);',
'    v_tot_emps NUMBER;',
'    vResEjec NUMBER;',
'    v_cons_sol NUMBER; -- Recibe vConsecutivo',
'    v_mot VARCHAR2(255); -- Recibe vConsecutivo',
'    v_periodo_result VARCHAR2(25);',
'    v_count_func NUMBER := 0; ',
'BEGIN',
'    v_emps := :P13_LISTA_FUNCIONARIOS;',
'    v_emps_tab := apex_util.string_to_table(v_emps, '':'');',
'    vcant_dias := TO_NUMBER(:P13_CANTIDAD_DE_DIAS);',
'    v_tot_emps := v_emps_tab.COUNT;   ',
'    :P13_VALIDACION_MSG := NULL;',
'    :P13_MSG_SINSELECCION := NULL;',
'    ',
'      SELECT COUNT(*)',
'          INTO v_count_func',
'          FROM SOLICITUDES_VACACIONES_LEGALES',
'          WHERE ID_VACACION_COLECTIVA = :P13_ID_VACACION_COLECTIVA;    ',
'          ',
'            IF (v_emps IS NULL OR v_emps_tab.COUNT = 0) AND v_count_func = 0 THEN         ',
'              :P13_VALIDACION_MSG := ''Debes seleccionar al menos una persona funcionaria.'';',
'              RETURN;',
'            ELSE  ',
'            IF (v_emps IS NULL OR v_emps_tab.COUNT = 0) AND v_count_func > 0 THEN',
unistr('                     :P13_MSG_SINSELECCION := ''Actualmente no se han seleccionado nuevas personas funcionarias para la vacaci\00F3n colectiva. Sin embargo puedes finalizar el proceso presionando "Siguiente"'';'),
'                      RETURN;',
'                END IF;',
'            FOR i IN 1..v_emps_tab.COUNT LOOP    ',
'     ',
'                v_emp_id := v_emps_tab(i);',
'                v_periodo_result := PKG_UTILIDADES.f_get_max_periodo_empleado(v_emp_id);',
'                vnom_emp := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_emp_id);',
'',
'                v_id_sol := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'                v_nom_sol := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_id_sol);',
'',
'                v_cur := PKG_PLANI.f_obtener_jefe_x_cod_sirh(v_emp_id);',
'                FETCH v_cur INTO vIdJefe, vNomJefe;',
'                CLOSE v_cur;',
'',
'                vmail_emp := PKG_PLANI.f_get_correo_emp_x_cod_sirh(v_emp_id);',
'                vmail_jefe := PKG_PLANI.f_get_correo_emp_x_cod_sirh(vIdJefe);',
'',
'                v_mot := PKG_COLECTIVAS.f_obtener_motivo_vacacion(:P13_ID_VACACION_COLECTIVA);',
'',
'                PKG_COLECTIVAS.sp_aplicar_vacacion_colectiva(v_emp_id, :P13_FECHA_INICIO,:P13_FECHA_FIN, vcant_dias, NULL, :P13_ID_VACACION_COLECTIVA, 11, ''AP'', :APP_USER, vResEjec, v_cons_sol);',
'',
'                IF vResEjec = 1 THEN',
'                    PKG_CORREOS.sp_enviar_correo_html(vmail_emp, vmail_jefe, 11,',
'                                                     ''NOMBRE='' || vnom_emp || ',
'                                                     '',ID_SOLICITUD_VACACION='' || v_cons_sol ||',
'                                                     '',PERIODO='' || v_periodo_result || ',
'                                                     '',FECHA_INICIAL='' || :P13_FECHA_INICIO ||',
'                                                     '',FECHA_FINAL='' || :P13_FECHA_FIN || ',
'                                                     '',CANTIDAD_DIAS='' || vcant_dias ||',
'                                                     '',MOTIVO='' || v_mot || ',
'                                                     '',ID_EMPLEADO_SOLICITA='' || v_nom_sol);',
'                ELSE',
unistr('                    DBMS_OUTPUT.PUT_LINE(''El procedimiento de registro fall\00F3.'');'),
'                END IF;',
unistr('                ---Enviamos las alertas de vacaciones colectivas en conflicto seg\00FAn corresponda             '),
'               PKG_COLECTIVAS.sp_obtiene_solcitudes_pend(v_emp_id,:P13_FECHA_INICIO,:P13_FECHA_FIN,:P13_ID_VACACION_COLECTIVA);                       ',
'            END LOOP;',
'        apex_util.set_session_state(''P13_PROGRESO'', ''COMPLETADO'');      ',
'        END IF;',
'END; '))
,p_attribute_02=>'P13_LISTA_FUNCIONARIOS,P13_PROGRESO,P13_ID_VACACION_COLECTIVA,P13_FECHA_INICIO,P13_FECHA_FIN,P13_CANTIDAD_DE_DIAS'
,p_attribute_03=>'P13_PROGRESO,P13_VALIDACION_MSG,P13_MSG_SINSELECCION'
,p_attribute_04=>'N'
,p_wait_for_result=>'Y'
);
