,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_count NUMBER;',
'    v_empleado_id VARCHAR2(4000);',
'    v_empleado_nombre VARCHAR2(4000); -- Variable para el nombre del empleado',
'    v_vacacion_colectiva_id NUMBER := :P13_ID_VACACION_COLECTIVA;',
'    v_error_message CLOB := '''';',
'BEGIN',
'    FOR i IN 1..APEX_UTIL.STRING_TO_TABLE(:P13_LISTA_FUNCIONARIOS).COUNT LOOP',
'        v_empleado_id := APEX_UTIL.STRING_TO_TABLE(:P13_LISTA_FUNCIONARIOS)(i);',
'',
'        -- Obtener el nombre del empleado',
'        SELECT NOMBRE || '' '' || PRIMER_APELLIDO || '' '' || SEGUNDO_APELLIDO AS NOMBRE -- Reemplaza ''nombre'' con el nombre de tu columna de nombres',
'        INTO v_empleado_nombre',
'        FROM empleados -- Reemplaza ''empleados'' con el nombre de tu tabla de empleados',
'        WHERE id_empleado = v_empleado_id; -- Reemplaza ''id_empleado'' con el nombre de tu columna de IDs',
'',
'        SELECT COUNT(*)',
'        INTO v_count',
'        FROM SOLICITUDES_VACACIONES_LEGALES',
'        WHERE ID_EMPLEADO = v_empleado_id',
'        AND ID_VACACION_COLECTIVA = v_vacacion_colectiva_id;',
'',
'        IF v_count > 0 THEN',
'            v_error_message := v_error_message || v_empleado_nombre || CHR(10);',
'        END IF;',
'    END LOOP;',
'    :P13_ERROR_MESSAGE := v_error_message;',
'END;'))
,p_attribute_02=>'P13_LISTA_FUNCIONARIOS,P13_ID_VACACION_COLECTIVA'
,p_attribute_03=>'P13_ERROR_MESSAGE'
,p_attribute_04=>'N'
,p_wait_for_result=>'Y'
);
