wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(581678534076809525)
,p_plug_name=>'Reporte de Saldos de Vacaciones'
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480144791966480508)
,p_plug_display_sequence=>30
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'		E.CODIGO_EMPLEADO_SIRH AS CODIGO_EMPLEADO, ',
'		E.CEDULA,',
'        PKG_REPORTES.f_replace_val_acentos(PKG_UTILIDADES.f_retorna_nombre_emp(SV.ID_EMPLEADO)) AS NOMBRE_EMPLEADO,',
'		UN.NOMBRE AS DEPARTAMENTO,',
'		SV.INICIO_PERIODO||''-''||SV.FIN_PERIODO AS PERIODO,',
'        SV.ACREDITADAS_HABILES AS DIAS_ACREDITADOS,',
'        SV.SALDO_HABIL AS SALDO_HABIL,',
'        PKG_REPORTES.f_obtiene_puesto_empleado(SV.ID_EMPLEADO) AS CARGO_EMPLEADO,',
'		DECODE(PKG_REPORTES.f_obtiene_estrato(SV.ID_EMPLEADO),''SUPERIOR'',''PROFESIONAL'',''EJECUTIVO'',''PROFESIONAL'',''PROFESIONAL'',''PROFESIONAL'',',
'        ''GERENCIAL'',''PROFESIONAL'',''ADMINISTRATIVO'',''TECNICO'',''OPERATIVO'',''TECNICO'',''CALIFICADO'',''TECNICO'',''TECNICO'',''TECNICO'') AS ESTRATO,',
'		TO_CHAR(SV.FECHA_ULTIMA_MODIFICACION,''DD/MM/YYYY'') AS FECHA_ULTIMA_MODIFICACION',
'FROM  EMPLEADOS@CONSULTA_ICT E ',
'		INNER JOIN USUARIOS@CONSULTA_ICT U ON U.CODIGO_EMPLEADO = E.CODIGO_EMPLEADO',
'		INNER JOIN EMPLEADOS EM ON EM.ID_EMPLEADO = E.CODIGO_EMPLEADO_SIRH',
'        INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON EM.ID_EMPLEADO = EIS.ID_EMPLEADO',
'        INNER JOIN MOVIMIENTOS_PERSONAL MP ON EM.ID_EMPLEADO = MP.ID_EMPLEADO',
'        INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'		INNER JOIN UNIDADES@CONSULTA_ICT UN ON UN.ID_UNIDADES = U.CODIGO_UNIDAD',
'		INNER JOIN SALDO_VACACIONES_LEGALES SV ON SV.ID_EMPLEADO = E.CODIGO_EMPLEADO_SIRH',
'        WHERE (:P15_DEPARTAMENTO IS NULL OR UN.ID_UNIDADES = :P15_DEPARTAMENTO)',
'		AND UN.PERIODO = TO_CHAR(SYSDATE,''YYYY'')',
'		AND (SV.SALDO_HABIL > 0 OR SV.SALDO_HABIL < 0)',
'        AND MP.INDICADOR_VIGENTE = 1 ',
'        AND E.CODIGO_ESTADO = 1 ',
'        AND U.ESTADO = 1;'))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_document_header=>'APEX'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
