 p_id=>wwv_flow_api.id(305645827739580630)
,p_process_sequence=>40
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_ENVIAR_INFO_VACAS_PROPO'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_periodo_habil VARCHAR2(100) := :P17_PERIODO_HABIL;',
'    v_inicio_periodo NUMBER;',
'    v_fin_periodo NUMBER;',
'    v_anio_actual NUMBER := EXTRACT(YEAR FROM SYSDATE);',
'    v_id_modificador NUMBER;',
'    v_acreditadas_habiles NUMBER;',
'    v_registro_ya_existe BOOLEAN;',
'BEGIN',
'',
'    v_inicio_periodo := TO_NUMBER(REGEXP_SUBSTR(v_periodo_habil, ''^\d+''));',
'    v_fin_periodo := TO_NUMBER(REGEXP_SUBSTR(v_periodo_habil, ''\d+$''));',
'    ',
'    IF v_fin_periodo = v_anio_actual THEN',
'        ',
'        v_id_modificador := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'        v_acreditadas_habiles := PKG_VACACIONES.f_obtiene_saldo_por_periodo(:P17_ID_EMPLEADO);',
'          ',
'          v_registro_ya_existe := PKG_VACACIONES.f_val_insert_saldo_vacaciones(',
'            p_id_empleado                   => :P17_ID_EMPLEADO,',
'            p_inicio_periodo                => v_fin_periodo,',
'            p_fin_periodo                   => v_fin_periodo + 1,',
'            p_acreditadas_habiles           => v_acreditadas_habiles,',
'            p_id_bitacora_acredi_vaca       => NULL,',
'            p_saldo_habil                   => 0,',
'            p_id_modificador                => v_id_modificador,',
'            p_fecha_ultima_modificacion     => SYSTIMESTAMP,',
'            p_motivo_modificacion           => NULL',
'        );',
'',
'        IF v_registro_ya_existe = false THEN',
'            :P17_PERIODO_HABIL := v_fin_periodo || ''-'' || (v_fin_periodo + 1);',
'        END IF;',
'        ',
'    END IF;',
'END;'))
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(583361299173253284)
,p_process_when=>'P17_FLAG'
,p_process_when_type=>'VAL_OF_ITEM_IN_COND_EQ_COND2'
,p_process_when2=>'4'
);
end;
