wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(581676223528809502)
,p_plug_name=>'Funcionarios con vacaciones colectivas aplicadas'
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480144791966480508)
,p_plug_display_sequence=>30
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'       E.CODIGO_EMPLEADO_SIRH AS CODIGO_EMPLEADO,',
'       E.CEDULA,',
'       PKG_UTILIDADES.f_retorna_nombre_emp(SV.ID_EMPLEADO) AS NOMBRE_EMPLEADO,',
'       UN.NOMBRE AS DEPARTAMENTO,',
'       PKG_REPORTES.f_obtiene_puesto_empleado(SV.ID_EMPLEADO) AS CARGO_EMPLEADO,',
'        DECODE(PKG_REPORTES.f_obtiene_estrato(SV.ID_EMPLEADO),''SUPERIOR'',''PROFESIONAL'',''EJECUTIVO'',''PROFESIONAL'',''PROFESIONAL'',''PROFESIONAL'',',
'        ''GERENCIAL'',''PROFESIONAL'',''ADMINISTRATIVO'',''TECNICO'',''OPERATIVO'',''TECNICO'',''CALIFICADO'',''TECNICO'',''TECNICO'',''TECNICO'') AS ESTRATO,',
'       VC.ID_VACACION_COLECTIVA,',
'       VC.MOTIVO,',
'       VC.FECHA_INICIO,',
'       VC.FECHA_FIN,',
'       TO_CHAR(VC.DIAS_VACACIONES, ''990D00'') AS DIAS_VACACIONES,',
'       VC.ID_MODIFICADOR,',
'       VC.FECHA_ULTIMA_MODIFICACION',
'FROM VACACIONES_COLECTIVAS VC ',
'	  INNER JOIN SOLICITUDES_VACACIONES_LEGALES SV ON SV.ID_VACACION_COLECTIVA = VC.ID_VACACION_COLECTIVA ',
'	  INNER JOIN EMPLEADOS@CONSULTA_ICT E ON E.CODIGO_EMPLEADO_SIRH =  SV.ID_EMPLEADO',
'      INNER JOIN EMPLEADOS EMP ON EMP.ID_EMPLEADO  = E.CODIGO_EMPLEADO_SIRH ',
'      INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON EMP.ID_EMPLEADO = EIS.ID_EMPLEADO',
'      INNER JOIN MOVIMIENTOS_PERSONAL MP ON EMP.ID_EMPLEADO = MP.ID_EMPLEADO',
'      INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'	  INNER JOIN USUARIOS@CONSULTA_ICT U ON U.CODIGO_EMPLEADO = E.CODIGO_EMPLEADO',
'	  INNER JOIN UNIDADES@CONSULTA_ICT UN ON UN.ID_UNIDADES = U.CODIGO_UNIDAD',
'	  WHERE VC.ID_VACACION_COLECTIVA =  :P19_MOTIVO ',
'	  AND UN.PERIODO = TO_CHAR(SYSDATE,''YYYY'')',
'	  AND SV.ESTADO_PROCESO = ''AP'' AND VC.ESTADO = ''A''',
'      AND MP.INDICADOR_VIGENTE = 1 ',
'      AND E.CODIGO_ESTADO = 1 ',
'      AND U.ESTADO = 1;',
'  '))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
,p_prn_height=>210
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header=>'Funcionarios con vacaciones colectivas aplicadas'
,p_prn_page_header_font_color=>'#000000'
,p_prn_page_header_font_family=>'Helvetica'
,p_prn_page_header_font_weight=>'normal'
