wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(581027392270421143)
,p_plug_name=>unistr('Reporte: M\00E1s de dos peri\00F3dos con saldo de vacaciones')
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480144791966480508)
,p_plug_display_sequence=>30
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'		PLA.CODIGO_EMPLEADO_SIRH,',
'        PLA.CEDULA AS CEDULA,',
'		PKG_UTILIDADES.f_retorna_nombre_emp(SV.ID_EMPLEADO) AS NOMBRE_EMPLEADO,',
'        UNI.NOMBRE AS DEPARTAMENTO,',
'		SV.INICIO_PERIODO||''-''||SV.FIN_PERIODO AS PERIODO,',
'        SV.ACREDITADAS_HABILES AS DIAS_ACREDITADOS,',
'        SV.SALDO_HABIL  AS SALDO_HABIL,',
'        PKG_REPORTES.f_obtiene_puesto_empleado(SV.ID_EMPLEADO) AS CARGO_EMPLEADO,',
'        DECODE(PKG_REPORTES.f_obtiene_estrato(SV.ID_EMPLEADO),''SUPERIOR'',''PROFESIONAL'',''EJECUTIVO'',''PROFESIONAL'',''PROFESIONAL'',''PROFESIONAL'',',
'        ''GERENCIAL'',''PROFESIONAL'',''ADMINISTRATIVO'',''TECNICO'',''OPERATIVO'',''TECNICO'',''CALIFICADO'',''TECNICO'',''TECNICO'',''TECNICO'') AS ESTRATO,',
'		TO_CHAR(SV.FECHA_ULTIMA_MODIFICACION,''DD/MM/YYYY'') AS FECHA_ULTIMA_MODIFICACION		',
'FROM    UNIDADES@CONSULTA_ICT UNI',
'		INNER JOIN USUARIOS@CONSULTA_ICT USU ON UNI.ID_UNIDADES = USU.CODIGO_UNIDAD',
'		INNER JOIN EMPLEADOS@CONSULTA_ICT PLA ON USU.CODIGO_EMPLEADO = PLA.CODIGO_EMPLEADO',
'        INNER JOIN EMPLEADOS E ON E.ID_EMPLEADO = PLA.CODIGO_EMPLEADO_SIRH',
'        INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'        INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'        INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'		INNER JOIN SALDO_VACACIONES_LEGALES SV on SV.ID_EMPLEADO =  PLA.CODIGO_EMPLEADO_SIRH',
'		WHERE EXTRACT(YEAR FROM SYSDATE) = UNI.PERIODO',
'		--AND (SV.SALDO_HABIL > 0 OR SV.SALDO_HABIL < 0)',
'        AND SV.SALDO_HABIL > 0 ',
'		AND (:P20_DEPARTAMENTO IS NULL OR UNI.ID_UNIDADES = :P20_DEPARTAMENTO)',
'        AND MP.INDICADOR_VIGENTE = 1 ',
'        AND PLA.CODIGO_ESTADO = 1 ',
'        AND USU.ESTADO = 1',
'		AND (SELECT COUNT(SV2.ID_EMPLEADO)',
'				FROM SALDO_VACACIONES_LEGALES SV2',
'				WHERE SV2.ID_EMPLEADO = PLA.CODIGO_EMPLEADO_SIRH ',
'				AND SV2.SALDO_HABIL > 0) > 2',
'        ',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_document_header=>'APEX'
,p_prn_units=>'MILLIMETERS'
