,p_plug_display_sequence=>30
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'		--SV.ID_INSTITUCION_SIRHP,',
'		SV.ID_EMPLEADO,',
'        PKG_UTILIDADES.f_retorna_nombre_emp(SV.ID_EMPLEADO) AS NOMBRE,',
'		UNI.NOMBRE AS DEPARTAMENTO,',
'		SV.ID_SOLICITUD_VACACION,',
'		SV.ID_VACACION_COLECTIVA,',
'		--SV.ID_ESTADO,',
'		SV.FECHA_REGISTRO,',
'		SV.FECHA_INICIO,',
'		--SV.INDICADOR_INICIO_MEDIODIA,',
'		SV.FECHA_FIN,',
'		--SV.INDICADOR_FINAL_MEDIODIA,',
'		SV.DIAS_VACACIONES,',
'        SV.ID_ESTADO AS ESTADO_PROCESO,',
'		--SV.TIPO_SOLICITUD,',
'		--SV.ID_MODIFICADOR,',
'		--SV.FECHA_ULTIMA_MODIFICACION,',
'	    --TO_CHAR(SV.MOTIVO) AS MOTIVO,',
'		--TO_CHAR(SV.MOTIVO_DENEGATORIA) AS MOTIVO_DENEGATORIA,',
'		--TO_CHAR(SV.OBSERVACIONES) AS OBSERVACIONES,',
'		--SV.NOMBRE_DEPENDENCIA,',
'		--SV.ID_DEPENDENCIA,',
'		--SV.ID_EMPLEADO_JEFE,',
'		--SV.ID_SUSTITUYE,',
'		SV.ID_SOLICITUD_DEVOLUCION_VACAC',
'		--SV.ID_INCAPACIDAD_EMPLEADO',
'FROM',
'		SOLICITUDES_VACACIONES_LEGALES  SV',
'        INNER JOIN EMPLEADOS E ON E.ID_EMPLEADO = SV.ID_EMPLEADO',
'        INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'        INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'        INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'		INNER JOIN EMPLEADOS@CONSULTA_ICT PLA ON PLA.CODIGO_EMPLEADO_SIRH = SV.ID_EMPLEADO',
'		INNER JOIN USUARIOS@CONSULTA_ICT USU ON USU.CODIGO_EMPLEADO = PLA.CODIGO_EMPLEADO',
'		INNER JOIN UNIDADES@CONSULTA_ICT UNI ON UNI.ID_UNIDADES = USU.CODIGO_UNIDAD',
'		WHERE  UNI.PERIODO = TO_CHAR(SYSDATE,''YYYY'') ',
'            AND MP.INDICADOR_VIGENTE = 1 ',
'            AND PLA.CODIGO_ESTADO = 1 ',
'            AND USU.ESTADO = 1',
'            AND (:P21_DEPARTAMENTO IS NULL OR UNI.ID_UNIDADES = :P21_DEPARTAMENTO)',
'            AND (TRUNC(SV.FECHA_INICIO) BETWEEN NVL(:P21_FECHA_INICIO, TRUNC(SV.FECHA_INICIO))',
'            AND NVL(:P21_FECHA_FINAL, TRUNC(SV.FECHA_INICIO)))'))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
,p_prn_height=>210
,p_prn_orientation=>'HORIZONTAL'
,p_prn_page_header=>'Detalle boletas de vacaciones funcionarios ICT'
