wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(871985059517231307)
,p_plug_name=>'Reporte de vacaciones disfrutadas por empleado'
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480144791966480508)
,p_plug_display_sequence=>30
,p_include_in_reg_disp_sel_yn=>'Y'
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'        E.CODIGO_EMPLEADO_SIRH AS CODIGO_EMPLEADO, ',
'        E.CEDULA,',
'        PKG_UTILIDADES.f_retorna_nombre_emp(E.CODIGO_EMPLEADO_SIRH) AS NOMBRE,',
'        UN.NOMBRE AS DEPARTAMENTO,',
'        (TRUNC(DV.INICIO_PERIODO / 2) * 2) || ''-'' || (TRUNC(DV.INICIO_PERIODO / 2) * 2 + 1) AS PERIODO,',
'        NVL(SUM(DV.DIAS_VACACIONES), 0) - NVL(SUM(DV.DIAS_DEVUELTOS), 0) AS DIAS_VACACIONES_DISFRUTADAS',
'FROM EMPLEADOS@CONSULTA_ICT E',
'        INNER JOIN USUARIOS@CONSULTA_ICT U ON U.CODIGO_EMPLEADO = E.CODIGO_EMPLEADO',
'        INNER JOIN EMPLEADOS EM ON EM.ID_EMPLEADO = E.CODIGO_EMPLEADO_SIRH',
'        INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON EM.ID_EMPLEADO = EIS.ID_EMPLEADO',
'        INNER JOIN MOVIMIENTOS_PERSONAL MP ON EM.ID_EMPLEADO = MP.ID_EMPLEADO',
'        INNER JOIN UNIDADES@CONSULTA_ICT UN ON UN.ID_UNIDADES = U.CODIGO_UNIDAD',
'        INNER JOIN DISTRIBUCION_DIAS_VACACIONES DV ON DV.ID_EMPLEADO = E.CODIGO_EMPLEADO_SIRH',
'WHERE ',
'        UN.ID_UNIDADES = :P22_DEPARTAMENTO',
'        AND UN.PERIODO = TO_CHAR(SYSDATE, ''YYYY'')',
'        AND MP.INDICADOR_VIGENTE = 1 ',
'        AND E.CODIGO_ESTADO = 1 ',
'        AND U.ESTADO = 1',
'        AND DV.INICIO_PERIODO > 0',
'        AND DV.FIN_PERIODO > 0',
'GROUP BY ',
'        E.CODIGO_EMPLEADO_SIRH,',
'        E.CEDULA,',
'        EM.ID_EMPLEADO,',
'        UN.NOMBRE, ',
'        TRUNC(DV.INICIO_PERIODO / 2)'))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_units=>'MILLIMETERS'
,p_prn_paper_size=>'A4'
,p_prn_width=>297
,p_prn_height=>210
,p_prn_orientation=>'HORIZONTAL'
