wwv_flow_api.create_page_da_action(
 p_id=>wwv_flow_api.id(308256535143892675)
,p_event_id=>wwv_flow_api.id(308256057765892676)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_cantidad_dias number(10) := 0;',
'    v_cantidad_dias_feriados number(10) := 0;',
'    v_fecha_inicio DATE;',
'    v_fecha_fin DATE;',
'    v_fecha_ultima_acreditacion DATE;',
'    v_meses_completos NUMBER;',
'BEGIN',
'    -- Only proceed if both date fields have a value to prevent conversion errors',
'    IF :P23_DESDE IS NOT NULL AND :P23_HASTA IS NOT NULL THEN',
'        -- Convert the APEX item values to DATE variables',
'        v_fecha_inicio := TO_DATE(:P23_DESDE, ''DD/MM/YYYY'');',
'        v_fecha_fin := TO_DATE(:P23_HASTA, ''DD/MM/YYYY'');',
'        ',
'        -- Use V() to safely reference the long item name',
'        IF V(''P23_ULTIMA_ACREDITACION_VACACIONES'') IS NOT NULL THEN',
'            v_fecha_ultima_acreditacion := TO_DATE(V(''P23_ULTIMA_ACREDITACION_VACACIONES''), ''DD/MM/YYYY'');',
'            v_meses_completos := FLOOR(MONTHS_BETWEEN(v_fecha_fin, v_fecha_ultima_acreditacion));',
'            :P23_CANTIDAD_MESES_CUMPLIDOS := v_meses_completos;',
'        END IF;',
'        ',
'        -- Calculate business and holiday days',
'        v_cantidad_dias := PKG_UTILIDADES.f_dias_laborables(v_fecha_inicio, v_fecha_fin);',
'        v_cantidad_dias_feriados := PKG_VACACIONES.f_cant_dias_feriados(v_fecha_inicio, v_fecha_fin);',
'        ',
'        -- Assign the final calculated values back to the APEX items',
'        :P23_CANTIDAD_DE_DIAS := v_cantidad_dias - v_cantidad_dias_feriados;',
'        :P23_CANTIDAD_DE_DIAS_FERIADOS := v_cantidad_dias_feriados;',
'    END IF;',
'END;'))
,p_attribute_02=>'P23_CANTIDAD_DE_DIAS,P23_DESDE,P23_HASTA,P23_ULTIMA_ACREDITACION_VACACIONES'
,p_attribute_03=>'P23_CANTIDAD_DE_DIAS,P23_CANTIDAD_DE_DIAS_FERIADOS,P23_CANTIDAD_MESES_CUMPLIDOS'
,p_attribute_04=>'N'
,p_wait_for_result=>'Y'
);
