,p_action=>'NATIVE_EXECUTE_PLSQL_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'  v_dias_acreditables_x_periodo NUMBER(10,2);',
'  v_factor_proporcional         NUMBER(10,2);',
'  v_cantidad_meses_cumplidos    NUMBER(10,2);',
'  v_cantidad_dias_disponibles   NUMBER(10,2);',
'  v_cantidad_dias_vacas_propo   NUMBER(10,2);',
'  v_saldo_habil_periodo         NUMBER(10,2);',
'',
'BEGIN',
'  ',
'  v_dias_acreditables_x_periodo := :P23_DIAS_ACREDITABLES;',
'  v_factor_proporcional := :P23_FACTOR_PROPORCIONAL;',
'  v_cantidad_meses_cumplidos := :P23_CANTIDAD_MESES_CUMPLIDOS;',
'  v_saldo_habil_periodo := :P23_SALDO_HABIL;',
'  ',
'  v_cantidad_dias_vacas_propo := v_factor_proporcional * v_cantidad_meses_cumplidos;',
'  ',
'  IF v_cantidad_dias_vacas_propo <= v_dias_acreditables_x_periodo THEN',
'  ',
'      v_cantidad_dias_disponibles := (v_saldo_habil_periodo + v_cantidad_dias_vacas_propo);',
'      :P23_CANTIDAD_DIAS_DISPONIBLES := TO_CHAR(PKG_ACREDITA_VACACIONES.F_REDONDEAR_DIAS_ACRED(v_cantidad_dias_disponibles), ''999G990D00'');',
'       --:P23_CANTIDAD_DIAS_DISPONIBLES := TO_CHAR(v_cantidad_dias_disponibles, ''999G990D00'');',
'  END IF;',
'',
'END;'))
,p_attribute_02=>'P23_SALDO_HABIL,P23_DIAS_ACREDITABLES,P23_FACTOR_PROPORCIONAL,P23_CANTIDAD_MESES_CUMPLIDOS'
,p_attribute_03=>'P23_CANTIDAD_DIAS_DISPONIBLES'
,p_attribute_04=>'N'
,p_wait_for_result=>'Y'
);
end;
