,p_plug_name=>'lncapacidades y licencias sin goce de salario'
,p_region_template_options=>'#DEFAULT#'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480170240458480526)
,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    ID_EMPLEADO,',
'    NOMBRE_EMPLEADO,',
'    ID_REGISTRO,',
'    TIPO_REGISTRO,',
'    DESDE,',
'    HASTA,',
'    TIPO,',
'    MOTIVO,',
'    CANTIDAD_DIAS,',
'    INICIO_PERIODO,',
'    FIN_PERIODO,',
'    NUMERO_BOLETA,',
'    FECHA_REGISTRO,',
'    FECHA_CREACION,',
'    CANT_DIAS_RES,',
'    CANT_DIAS_RES_REDON,',
'    FACTOR_PROPORCIONAL',
'FROM (',
'    SELECT',
'        i.ID_EMPLEADO,',
'        PKG_REPORTES.f_replace_val_acentos(PKG_UTILIDADES.f_retorna_nombre_emp(i.ID_EMPLEADO)) AS NOMBRE_EMPLEADO,',
'        i.ID_INCAPACIDAD AS ID_REGISTRO,',
'        ''INCAPACIDAD'' AS TIPO_REGISTRO,',
'        i.DESDE,',
'        i.HASTA,',
'        i.TIPO_INCAPACIDAD AS TIPO,',
'        i.MOTIVO_INCAPACIDAD AS MOTIVO,',
'        i.CANTIDAD_DIAS_INCA AS CANTIDAD_DIAS,',
'        i.INICIO_PERIODO,',
'        i.FIN_PERIODO,',
'        i.NUMERO_BOLETA,',
'        i.FECHA_REGISTRO,',
'        i.FECHA_CREACION,',
'        i.CANT_DIAS_RES,',
'        i.CANT_DIAS_RES_REDON,',
'        i.FACTOR_PROPORCIONAL',
'    FROM BITA_RESTA_DIAS_INCAP i',
'',
'    UNION ALL',
'',
'    SELECT',
'        l.ID_EMPLEADO,',
'        PKG_REPORTES.f_replace_val_acentos(PKG_UTILIDADES.f_retorna_nombre_emp(l.ID_EMPLEADO)) AS NOMBRE_EMPLEADO,',
'        l.ID_LICENCIA AS ID_REGISTRO,',
'        ''LICENCIA'' AS TIPO_REGISTRO,',
'        l.DESDE,',
'        l.HASTA,',
'        l.TIPO_LICENCIA AS TIPO,',
'        NULL AS MOTIVO,',
'        l.CANTIDAD_DIAS_LIC AS CANTIDAD_DIAS,',
'        l.INICIO_PERIODO,',
'        l.FIN_PERIODO,',
'        NULL AS NUMERO_BOLETA,',
'        l.FECHA_REGISTRO,',
'        l.FECHA_CREACION,',
'        l.CANT_DIAS_RES,',
'        l.CANT_DIAS_RES_REDON,',
'        l.FACTOR_PROPORCIONAL',
'    FROM BITA_RESTA_DIAS_LIC l',
')',
'WHERE (:P24_FUNCIONARIO IS NULL OR ID_EMPLEADO = :P24_FUNCIONARIO)',
'AND (:P24_PERIODO_HABIL IS NULL OR  INICIO_PERIODO = TO_NUMBER(SUBSTR(:P24_PERIODO_HABIL, 1, 4)))',
'AND (:P24_PERIODO_HABIL IS NULL OR FIN_PERIODO = TO_NUMBER(SUBSTR(:P24_PERIODO_HABIL, 6, 4)))',
''))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_content_disposition=>'ATTACHMENT'
,p_prn_document_header=>'APEX'
