wwv_flow_api.create_page_item(
 p_id=>wwv_flow_api.id(311602094947211440)
,p_name=>'P24_FUNCIONARIO'
,p_item_sequence=>10
,p_item_plug_id=>wwv_flow_api.id(311601989382211439)
,p_prompt=>'Funcionario'
,p_display_as=>'NATIVE_POPUP_LOV'
,p_named_lov=>'LOV_FUNCIONARIOS_ACTIVOS'
,p_lov=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'    E.ID_EMPLEADO,',
'    E.NOMBRE || '' '' || E.PRIMER_APELLIDO || '' '' || E.SEGUNDO_APELLIDO AS NOMBRE',
'FROM EMPLEADOS E',
'INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'INNER JOIN EMPLEADOS@CONSULTA_ICT EMP ON E.ID_EMPLEADO = EMP.CODIGO_EMPLEADO_SIRH',
'INNER JOIN USUARIOS@CONSULTA_ICT USU ON EMP.CODIGO_EMPLEADO = USU.CODIGO_EMPLEADO',
'WHERE MP.INDICADOR_VIGENTE = 1 ',
'AND EMP.CODIGO_ESTADO = 1 ',
'AND USU.ESTADO = 1',
'ORDER BY NOMBRE ASC;'))
,p_lov_display_null=>'YES'
,p_lov_null_text=>'- Seleccionar -'
,p_cSize=>30
,p_field_template=>wwv_flow_api.id(480233150196480585)
,p_item_icon_css_classes=>'fa-search'
,p_item_template_options=>'#DEFAULT#'
,p_lov_display_extra=>'YES'
,p_attribute_01=>'POPUP'
,p_attribute_02=>'FIRST_ROWSET'
,p_attribute_03=>'N'
,p_attribute_04=>'N'
,p_attribute_05=>'N'
,p_attribute_07=>'Personas Funcionarias'
);
wwv_flow_api.create_page_item(
 p_id=>wwv_flow_api.id(311602163368211441)
,p_name=>'P24_PERIODO_HABIL'
,p_item_sequence=>20
,p_item_plug_id=>wwv_flow_api.id(311601989382211439)
,p_prompt=>unistr('Periodo H\00E1bil')
,p_display_as=>'NATIVE_SELECT_LIST'
,p_named_lov=>'LOV_PERIODOS_HABILES'
,p_lov=>wwv_flow_string.join(wwv_flow_t_varchar2(
'/*SELECT (EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, -12 * LEVEL)) + 0) || ''-'' ||',
'       (EXTRACT(YEAR FROM ADD_MONTHS(SYSDATE, -12 * LEVEL)) + 1) AS R',
'FROM DUAL',
'CONNECT BY LEVEL <= EXTRACT(YEAR FROM SYSDATE) - 2020 + 1',
'ORDER BY R;*/',
'',
'',
'',
'SELECT (start_year) || ''-'' || (start_year + 1) AS R',
'FROM (',
'    SELECT 2020 + LEVEL - 1 AS start_year',
'    FROM dual',
'    CONNECT BY 2020 + LEVEL - 1 <= EXTRACT(YEAR FROM SYSDATE)',
')',
'ORDER BY R;'))
,p_lov_display_null=>'YES'
