 p_id=>wwv_flow_api.id(302994748647565126)
,p_plug_name=>'Reporte: Saldo de Vacaciones Legales'
,p_region_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480145010443480508)
,p_plug_display_sequence=>10
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'    E.ID_EMPLEADO,',
'    E.ID_EMPLEADO AS NOMBRE,',
'    SVL.ID_INSTITUCION_SIRHP,',
'    SVL.INICIO_PERIODO,',
'    SVL.FIN_PERIODO,',
'    SVL.ACREDITADAS_HABILES,',
'    SVL.SALDO_HABIL,',
'    SVL.ID_MODIFICADOR,',
'    SVL.FECHA_ULTIMA_MODIFICACION',
'FROM EMPLEADOS E',
'INNER JOIN SALDO_VACACIONES_LEGALES SVL ON E.ID_EMPLEADO = SVL.ID_EMPLEADO',
'INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'INNER JOIN EMPLEADOS@CONSULTA_ICT EMP ON E.ID_EMPLEADO = EMP.CODIGO_EMPLEADO_SIRH',
'INNER JOIN USUARIOS@CONSULTA_ICT USU ON EMP.CODIGO_EMPLEADO = USU.CODIGO_EMPLEADO',
'WHERE MP.INDICADOR_VIGENTE = 1 ',
'AND EMP.CODIGO_ESTADO = 1 ',
'AND USU.ESTADO = 1;'))
,p_plug_source_type=>'NATIVE_IG'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_content_disposition=>'ATTACHMENT'
