,p_name=>'P26_ID_EMPLEADO'
,p_source_data_type=>'NUMBER'
,p_is_required=>true
,p_is_primary_key=>true
,p_item_sequence=>40
,p_item_plug_id=>wwv_flow_api.id(302984267430565149)
,p_item_source_plug_id=>wwv_flow_api.id(302984267430565149)
,p_prompt=>'Nombre del Empleado'
,p_source=>'ID_EMPLEADO'
,p_source_type=>'REGION_SOURCE_COLUMN'
,p_display_as=>'NATIVE_SELECT_LIST'
,p_named_lov=>'LOV_FUNCIONARIOS_ACTIVOS'
,p_lov=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'    E.ID_EMPLEADO,',
'    E.NOMBRE || '' '' || E.PRIMER_APELLIDO || '' '' || E.SEGUNDO_APELLIDO AS NOMBRE',
'FROM EMPLEADOS E',
'INNER JOIN EMPLEADOS_INSTITUCION_SIRHP EIS ON E.ID_EMPLEADO = EIS.ID_EMPLEADO',
'INNER JOIN MOVIMIENTOS_PERSONAL MP ON E.ID_EMPLEADO = MP.ID_EMPLEADO',
'INNER JOIN DETALLE_MOVIMIENTO DM ON MP.ID_MOVIMIENTO_PERSONAL = DM.ID_MOVIMIENTO_PERSONAL',
'INNER JOIN EMPLEADOS@CONSULTA_ICT EMP ON E.ID_EMPLEADO = EMP.CODIGO_EMPLEADO_SIRH',
'INNER JOIN USUARIOS@CONSULTA_ICT USU ON EMP.CODIGO_EMPLEADO = USU.CODIGO_EMPLEADO',
'WHERE MP.INDICADOR_VIGENTE = 1 ',
'AND EMP.CODIGO_ESTADO = 1 ',
'AND USU.ESTADO = 1',
'ORDER BY NOMBRE ASC;'))
,p_lov_display_null=>'YES'
,p_cHeight=>1
,p_read_only_when=>'P26_ID_EMPLEADO'
,p_read_only_when_type=>'ITEM_IS_NOT_NULL'
