,p_source=>'INICIO_PERIODO'
,p_source_type=>'REGION_SOURCE_COLUMN'
,p_display_as=>'NATIVE_SELECT_LIST'
,p_lov=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'    year_value AS display_value,',
'    year_value AS return_value',
'FROM',
'    (',
'        SELECT',
'            EXTRACT(YEAR FROM SYSDATE) + 1 - LEVEL AS year_value -- Start the list one year *after* the current year',
'        FROM',
'            DUAL',
'        CONNECT BY',
'            LEVEL <= (EXTRACT(YEAR FROM SYSDATE) - 2000 + 1) -- Generate one extra row for the future year',
'    )',
'WHERE',
'    year_value >= 2000 -- Keep the lower bound at 1981',
'ORDER BY',
'    year_value DESC;'))
,p_lov_display_null=>'YES'
,p_lov_null_text=>'- Seleccione -'
,p_cHeight=>1
,p_read_only_when=>'P26_INICIO_PERIODO'
