wwv_flow_api.create_page_validation(
 p_id=>wwv_flow_api.id(302969370890046823)
,p_validation_name=>'VAL_SALDO_HABIL_VS_DIAS_ACREDITADOS'
,p_validation_sequence=>90
,p_validation=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
unistr('    v_dias_acreditados NUMBER := :P26_ACREDITADAS_HABILES; -- Reemplaza P2_ con el prefijo de tu p\00E1gina'),
unistr('    v_saldo_habil      NUMBER := :P26_SALDO_HABIL;         -- Reemplaza P2_ con el prefijo de tu p\00E1gina'),
'BEGIN',
'    -- Solo valida si ambos campos tienen valores',
'    IF v_dias_acreditados IS NOT NULL AND v_saldo_habil IS NOT NULL THEN',
'        IF v_saldo_habil > v_dias_acreditados THEN',
unistr('            RETURN FALSE; -- Si es mayor, la validaci\00F3n falla'),
'        END IF;',
'        IF ABS(v_saldo_habil) > v_dias_acreditados THEN',
'            RETURN FALSE; ',
'        END IF;',
'    END IF;',
unistr('    RETURN TRUE; -- Si no es mayor o si alguno es nulo, la validaci\00F3n pasa'),
'END;'))
,p_validation_type=>'FUNC_BODY_RETURNING_BOOLEAN'
,p_error_message=>unistr('El Saldo H\00E1bil no puede ser mayor que los D\00EDas Acreditados H\00E1biles. O en caso de Saldo H\00E1bil ser negativo no debe ser mayor a los d\00EDas acreditados a pesar de ser negativo.')
,p_always_execute=>'Y'
,p_associated_item=>wwv_flow_api.id(302987020530565137)
,p_error_display_location=>'INLINE_WITH_FIELD'
);
