wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(327085201809819746)
,p_plug_name=>'Solicitudes de Vacaciones'
,p_parent_plug_id=>wwv_flow_api.id(327211090980651106)
,p_region_template_options=>'#DEFAULT#:t-Region--accent5:t-Region--scrollBody:margin-top-sm'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480172181371480527)
,p_plug_display_sequence=>10
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'    e.id_empleado,',
'    sv.ID_SOLICITUD_VACACION,',
'    sv.ID_VACACION_COLECTIVA,',
'    CAST(sv.fecha_inicio AS DATE) AS DESDE, ',
'    CAST(sv.fecha_fin AS DATE) AS HASTA,',
'    to_char(sv.dias_vacaciones, ''990D0'') AS CANTIDAD_DIAS,',
'    sv.ID_ESTADO,',
'    -- Columna con el texto completo',
'    UPPER(sv.MOTIVO_DENEGATORIA) AS MOTIVO_DENEGATORIA',
'FROM empleados e',
'    INNER JOIN solicitudes_vacaciones_legales sv ON e.id_empleado = sv.id_empleado',
'    INNER JOIN DISTRIBUCION_DIAS_VACACIONES dv ON sv.ID_SOLICITUD_VACACION = dv.ID_SOLICITUD_VACACION',
'    INNER JOIN ESTADOS_VACACIONES ev ON sv.ID_ESTADO = ev.ID_ESTADO',
'WHERE ',
'    e.cedula = :P30_CEDULA',
'    AND dv.INICIO_PERIODO = :P30_PERIODO_INICIO',
'    AND dv.FIN_PERIODO = :P30_PERIODO_FIN;'))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P30_CEDULA,P30_PERIODO_INICIO,P30_PERIODO_FIN'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>'Solicitudes de Vacaciones'
);
