wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(327102737461819846)
,p_plug_name=>unistr('Devoluci\00F3n de Vacaciones')
,p_parent_plug_id=>wwv_flow_api.id(327211090980651106)
,p_region_template_options=>'#DEFAULT#:t-Region--accent4:t-Region--scrollBody'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480172181371480527)
,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'	e.id_empleado,',
'    sv.ID_SOLICITUD_VACACION,',
'    sv.ID_SOLICITUD_DEVOLUCION_VACAC,',
'	CAST(sv.fecha_inicio AS DATE) as "DESDE", ',
'	CAST(sv.fecha_fin AS DATE) AS "HASTA",',
'    to_char(sv.dias_vacaciones, ''990D00'') AS CANTIDAD_DIAS,',
'	sv.ID_ESTADO,',
'    UPPER(sv.MOTIVO_DENEGATORIA) AS "MOTIVO_DENEGATORIA"',
'FROM empleados e',
'	INNER JOIN solicitudes_vacaciones_legales sv ON e.id_empleado = sv.id_empleado',
'	INNER JOIN DISTRIBUCION_DIAS_VACACIONES dv ON sv.ID_SOLICITUD_DEVOLUCION_VACAC = dv.ID_SOLICITUD_VACACION'))
,p_plug_source_type=>'NATIVE_IG'
,p_master_region_id=>wwv_flow_api.id(327085201809819746)
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_prn_page_header=>unistr('Devoluci\00F3n de Vacaciones')
);
