,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'PRC_CANCELAR_SOLICITUD'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_cursor SYS_REFCURSOR;',
'    vNombreJefe VARCHAR2(100);',
'	vId_Jefe NUMBER; ',
'    vnombre_empleado VARCHAR2(255);',
'    vcorreo_destino_emp VARCHAR2(255);',
'    vcorreo_destino_jefe VARCHAR2(255);',
'    v_id_empleado_cancela NUMBER;',
'    v_nombre_empleado_cancela VARCHAR (255);',
'    v_cantidad_dias NUMBER (5,1);',
'    vid_estado NUMBER;',
'    v_resultado NUMBER;',
'    v_text_cant_dias VARCHAR2(50);',
'    ',
'    v_codigo_estado CHAR(2);',
'    v_tipo_solicitud CHAR(2);',
'    ',
'BEGIN',
'    ',
unistr('    -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'    CASE :ID_MODULO_SIS',
'        WHEN 1 THEN ',
'            vid_estado := 16;',
'        WHEN 3 THEN ',
'            vid_estado := 10;',
'        ELSE ',
'            vid_estado := NULL;',
'    END CASE;',
'    ',
'    v_cantidad_dias := TO_NUMBER(:P113_DIAS);',
'    v_id_empleado_cancela := PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER);',
'    ',
'    v_text_cant_dias := TO_CHAR(:P113_DIAS);    ',
'    ',
'    IF :P113_DIAS = 0 THEN',
'        v_cantidad_dias := 0.5;',
'        v_text_cant_dias := ''0.5'';',
'	ELSE',
'        v_cantidad_dias := :P113_DIAS;',
'    END IF;',
'    ',
'    ',
'    --Obtenemos el estado de la solicitud de vacaciones ',
'    v_codigo_estado := PKG_DEVOLUCION.f_get_cod_estado_soli_vaca(:P113_ID_SOLICITUD);',
'    ',
'    --Obtenemos el tipo de solicitud de vacaciones',
'    v_tipo_solicitud := PKG_DEVOLUCION.f_get_tipo_soli_vaca(:P113_ID_SOLICITUD);',
'    ',
'    PKG_DEVOLUCION.sp_devolucion_vacaciones(',
'        PId_Empleado => :P113_ID_EMPLEADO,     ',
'        PDias => v_cantidad_dias,      ',
'        PPeriodo_Inicio => :P113_PERIODO_INICIO,',
'        PConsecutivo => :P113_ID_SOLICITUD,',
'        PJustificacion => NULL, ',
'        PId_Modificador => v_id_empleado_cancela,',
'        Pid_estado => vid_estado,',
'        pestado => ''CA'',',
'        pTiposolicitud => v_tipo_solicitud,',
'        POUT_Resultado => v_resultado',
'    );',
'',
'    IF v_resultado = 1 THEN',
'        ',
'        vnombre_empleado := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(:P113_ID_EMPLEADO);',
'        -- Obtener el nombre del usuario que cancela',
'        v_nombre_empleado_cancela := PKG_PLANI.f_get_nombre_emp_x_cod_sirh(v_id_empleado_cancela);',
'        ',
unistr('        v_cursor := PKG_PLANI.f_obtener_jefe_x_cod_sirh(:P113_ID_EMPLEADO); -- Llamada a la funci\00F3n'),
'        FETCH v_cursor INTO vId_Jefe, vNombreJefe;',
'        CLOSE v_cursor;',
'',
'        -- Obtener el correo del funcionario y jefe',
'        vcorreo_destino_emp := PKG_PLANI.f_get_correo_emp_x_cod_sirh(:P113_ID_EMPLEADO);',
'        vcorreo_destino_jefe := PKG_PLANI.f_get_correo_emp_x_cod_sirh(vId_Jefe);',
'',
unistr('        -- Validar el m\00F3dulo que se ingreso para hacer la solicitud	'),
'        PKG_CORREOS.sp_enviar_correo_html(',
'               p_destinatario_in => vcorreo_destino_emp,',
'               p_cc_in => vcorreo_destino_jefe,',
'               p_id_mensaje => 4,',
'               p_parametros => ''NOMBRE='' || vnombre_empleado || ',
'                               '',ID_SOLICITUD_VACACION='' || :P113_ID_SOLICITUD ||',
'                               '',PERIODO='' || :P113_PERIODO ||',
'                               '',FECHA_INICIAL='' || :P113_DESDE || ',
'                               '',FECHA_FINAL='' || :P113_HASTA || ',
'                               '',CANTIDAD_DIAS='' || v_text_cant_dias ||',
'                               '',ID_EMPLEADO_CANCELA='' || v_nombre_empleado_cancela',
'        );',
'    END IF;',
'END;'))
,p_process_error_message=>'Error al cancelar la solicitud'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_api.id(350923754834701810)
,p_process_success_message=>unistr('Solicitud de vacaciones cancelada con \00E9xito')
);
end;
/
