,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'    e.ID_EMPLEADO,',
'    sv.ID_SOLICITUD_VACACION,',
'	sv.ID_VACACION_COLECTIVA,',
'	dv.INICIO_PERIODO||'' - ''|| dv.FIN_PERIODO AS PERIODO, ',
'    dv.INICIO_PERIODO,',
'    dv.FIN_PERIODO,',
'	CAST(sv.FECHA_INICIO AS DATE)  AS "DESDE", ',
'	CAST(sv.FECHA_FIN AS DATE) AS "HASTA", ',
'	to_char(sv.dias_vacaciones, ''990D0'') AS CANTIDAD_DIAS,',
'	ev.ID_ESTADO',
'FROM EMPLEADOS e',
'INNER JOIN SOLICITUDES_VACACIONES_LEGALES sv ON e.ID_EMPLEADO = sv.ID_EMPLEADO',
'INNER JOIN DISTRIBUCION_DIAS_VACACIONES dv ON sv.ID_SOLICITUD_VACACION = dv.ID_SOLICITUD_VACACION',
'INNER JOIN ESTADOS_VACACIONES ev ON sv.ID_ESTADO = ev.ID_ESTADO',
'WHERE e.ID_EMPLEADO = :P403_ID_EMPLEADO',
'AND sv.FECHA_INICIO >= (sysdate - 7)',
'AND ev.ESTADO_PROCESO = ''EA'';'))
