wwv_flow_api.create_page_plug(
 p_id=>wwv_flow_api.id(578028542193903839)
,p_plug_name=>'Vacaciones en Estudio por GTH'
,p_region_name=>'VAC_EGTH'
,p_parent_plug_id=>wwv_flow_api.id(568470809939446810)
,p_region_template_options=>'#DEFAULT#:t-BreadcrumbRegion--useBreadcrumbTitle'
,p_component_template_options=>'#DEFAULT#'
,p_plug_template=>wwv_flow_api.id(480181579163480534)
,p_plug_display_sequence=>20
,p_plug_display_point=>'BODY'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT DISTINCT',
'	e.ID_EMPLEADO,',
'    sv.ID_SOLICITUD_VACACION, ',
'	sv.ID_VACACION_COLECTIVA, ',
'	e.CEDULA, ',
'    (e.NOMBRE|| '' '' || e.PRIMER_APELLIDO || '' '' || e.SEGUNDO_APELLIDO) as "NOMBRE_COMPLETO", ',
'	dv.INICIO_PERIODO,',
'    dv.INICIO_PERIODO||'' - ''|| dv.FIN_PERIODO PERIODO,',
'    CAST(sv.FECHA_INICIO AS DATE) as "DESDE", ',
'	CAST(sv.FECHA_FIN AS DATE) AS "HASTA",',
'    to_char(sv.DIAS_VACACIONES, ''990D0'') AS CANTIDAD_DIAS,',
'	sv.FECHA_REGISTRO, ',
'    sv.ID_ESTADO',
'FROM EMPLEADOS e',
'	INNER JOIN SOLICITUDES_VACACIONES_LEGALES sv ON e.ID_EMPLEADO = sv.ID_EMPLEADO',
'	INNER JOIN DISTRIBUCION_DIAS_VACACIONES dv ON sv.ID_SOLICITUD_VACACION = dv.ID_SOLICITUD_VACACION',
'WHERE',
'	sv.ID_ESTADO = 17',
'    AND sv.ESTADO_PROCESO = ''EA''',
'	AND sv.FECHA_INICIO > (SYSDATE-60)',
'    AND sv.ID_EMPLEADO_JEFE = :P500_ID_EMPLEADO_JEFE'))
,p_plug_source_type=>'NATIVE_IG'
,p_ajax_items_to_submit=>'P500_ID_EMPLEADO_JEFE'
,p_plug_query_options=>'DERIVED_REPORT_COLUMNS'
,p_plug_display_condition_type=>'VAL_OF_ITEM_IN_COND_EQ_COND2'
,p_plug_display_when_condition=>'ID_MODULO_SIS'
,p_plug_display_when_cond2=>'1'
);
