,p_display_as=>'NATIVE_HIDDEN'
,p_attribute_01=>'Y'
);
wwv_flow_api.create_page_item(
 p_id=>wwv_flow_api.id(506201646471014670)
,p_name=>'P500_ID_EMPLEADO_JEFE'
,p_item_sequence=>10
,p_item_plug_id=>wwv_flow_api.id(567969659637599015)
,p_prompt=>'Buscar Por Unidad'
,p_display_as=>'NATIVE_POPUP_LOV'
,p_lov=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT',
'     uni.NOMBRE AS DISPLAY_VALUE,',
'     pla.CODIGO_EMPLEADO_SIRH AS RETURN_VALUE-- O usa el nombre completo del empleado',
'FROM MANTE.UNIDADES@CONSULTA_ICT uni',
'INNER JOIN COMPRA.USUARIOS@CONSULTA_ICT usu ON uni.LOGIN_JEFE = usu.LOGIN_USUARIO',
'INNER JOIN PLANI.EMPLEADOS@CONSULTA_ICT pla ON usu.CODIGO_EMPLEADO = pla.CODIGO_EMPLEADO',
'WHERE',
'    EXTRACT(YEAR FROM SYSDATE) = uni.PERIODO',
unistr('    -- L\00F3gica Condicional: Aplica el filtro de empleado SOLO si el ID del m\00F3dulo es 2'),
'    AND (',
unistr('        -- Condici\00F3n 1: Si ID_MODULO_SIS es 1, esta parte del WHERE se eval\00FAa como TRUE (se ignora el filtro de empleado)'),
'        :P500_ID_MODULO_SIS = 1',
'',
unistr('        -- Condici\00F3n 2: Si ID_MODULO_SIS es 2, se aplica el filtro del empleado'),
'        OR (',
'            :P500_ID_MODULO_SIS = 2',
'            AND pla.CODIGO_EMPLEADO_SIRH = PKG_PLANI.f_get_id_empleado_x_usuario(:APP_USER)',
'        )',
'    )',
'ORDER BY uni.NOMBRE ASC;'))
,p_lov_display_null=>'YES'
,p_cSize=>30
,p_field_template=>wwv_flow_api.id(480233150196480585)
,p_item_template_options=>'#DEFAULT#:t-Form-fieldContainer--large'
,p_lov_display_extra=>'YES'
,p_attribute_01=>'POPUP'
